15	
16	library ieee;
17	use ieee.std_logic_1164.all;
18	
19	
20	library surf;
21	use surf.StdRtlPkg.all;
22	use surf.AxiStreamPkg.all;
23	
24	package AxiDmaPkg is
25	
26	   -------------------------------------
27	   -- Write DMA Axi-Stream Configuration
28	   -------------------------------------
29	   constant AXIS_WRITE_DMA_CONFIG_C : AxiStreamConfigType := (
30	      TSTRB_EN_C    => false,
31	      TDATA_BYTES_C => 8,
32	      TDEST_BITS_C  => 8,
33	      TID_BITS_C    => 0,
34	      TKEEP_MODE_C  => TKEEP_COMP_C,
35	      TUSER_BITS_C  => 8,
36	      TUSER_MODE_C  => TUSER_FIRST_LAST_C);
37	
38	   -------------------------------------
39	   -- Write DMA Request (AxiStreamDmaWrite)
40	   -------------------------------------
41	
42	   -- Base Record
43	   type AxiWriteDmaReqType is record
44	      request : sl;
45	      drop    : sl;
46	      address : slv(63 downto 0);
47	      maxSize : slv(31 downto 0);
48	      prot    : slv(2 downto 0);
49	   end record;
50	
51	   -- Initialization constants
52	   constant AXI_WRITE_DMA_REQ_INIT_C : AxiWriteDmaReqType := (
53	      request => '0',
54	      drop    => '0',
55	      address => (others => '0'),
56	      maxSize => (others => '0'),
57	      prot    => (others => '0'));
58	
59	   -- Array
60	   type AxiWriteDmaReqArray is array (natural range<>) of AxiWriteDmaReqType;
61	
62	   -------------------------------------
63	   -- Write DMA Acknowledge (AxiStreamDmaWrite)
64	   -------------------------------------
65	
66	   -- Base Record
67	   type AxiWriteDmaAckType is record
68	      idle       : sl;
69	      done       : sl;
70	      size       : slv(31 downto 0);
71	      overflow   : sl;
72	      writeError : sl;
73	      errorValue : slv(1 downto 0);
74	      firstUser  : slv(7 downto 0);
75	      lastUser   : slv(7 downto 0);
76	      dest       : slv(7 downto 0);
77	      id         : slv(7 downto 0);
78	   end record;
79	
80	   -- Initialization constants
81	   constant AXI_WRITE_DMA_ACK_INIT_C : AxiWriteDmaAckType := (
82	      idle       => '1',
83	      done       => '0',
84	      size       => (others => '0'),
85	      overflow   => '0',
86	      writeError => '0',
87	      errorValue => "00",
88	      firstUser  => (others => '0'),
89	      lastUser   => (others => '0'),
90	      dest       => (others => '0'),
91	      id         => (others => '0')
92	      );
93	
94	   -- Array
95	   type AxiWriteDmaAckArray is array (natural range<>) of AxiWriteDmaAckType;
96	
97	   -------------------------------------
98	   -- Read DMA Request (AxiStreamDmaRead)
99	   -------------------------------------
100	
101	   -- Base Record
102	   type AxiReadDmaReqType is record
103	      request   : sl;
104	      address   : slv(63 downto 0);
105	      size      : slv(31 downto 0);
106	      firstUser : slv(7 downto 0);
107	      lastUser  : slv(7 downto 0);
108	      dest      : slv(7 downto 0);
109	      id        : slv(7 downto 0);
110	      prot      : slv(2 downto 0);
111	   end record;
112	
113	   -- Initialization constants
114	   constant AXI_READ_DMA_REQ_INIT_C : AxiReadDmaReqType := (
115	      request   => '0',
116	      address   => (others => '0'),
117	      size      => (others => '0'),
118	      firstUser => (others => '0'),
119	      lastUser  => (others => '0'),
120	      dest      => (others => '0'),
121	      id        => (others => '0'),
122	      prot      => (others => '0'));
123	
124	   -- Array
125	   type AxiReadDmaReqArray is array (natural range<>) of AxiReadDmaReqType;
126	
127	   constant AXI_READ_DMA_READ_REQ_SIZE_C : integer := 131;
128	
129	   function toSlv (r             : AxiReadDmaReqType) return slv;
130	   function toAxiReadDmaReq (din : slv; valid : sl) return AxiReadDmaReqType;
131	
132	   -------------------------------------
133	   -- Read DMA Acknowledge (AxiStreamDmaRead)
134	   -------------------------------------
135	
136	   -- Base Record
137	   type AxiReadDmaAckType is record
138	      idle       : sl;
139	      done       : sl;
140	      readError  : sl;
141	      errorValue : slv(1 downto 0);
142	   end record;
143	
144	   -- Initialization constants
145	   constant AXI_READ_DMA_ACK_INIT_C : AxiReadDmaAckType := (
146	      idle       => '1',
147	      done       => '0',
148	      readError  => '0',
149	      errorValue => "00"
150	      );
151	
152	   -- Array
153	   type AxiReadDmaAckArray is array (natural range<>) of AxiReadDmaAckType;
154	
155	
156	   -------------------------------------
157	   -- DMA Write Descriptor Request (AxiStreamDmaV2)
158	   -- Issued from dma write engine to request a free
159	   -- descriptor from the pool.
160	   -------------------------------------
161	
162	   type AxiWriteDmaDescReqType is record
163	      valid : sl;
164	      id    : slv(7 downto 0);
165	      dest  : slv(7 downto 0);
166	   end record;
167	
168	   constant AXI_WRITE_DMA_DESC_REQ_INIT_C : AxiWriteDmaDescReqType := (
169	      valid => '0',
170	      id    => (others => '0'),
171	      dest  => (others => '0')
172	      );
173	
174	   type AxiWriteDmaDescReqArray is array (natural range<>) of AxiWriteDmaDescReqType;
175	
176	   constant AXI_WRITE_DMA_DESC_REQ_SIZE_C : integer := 16;
177	
178	   function toSlv (r                  : AxiWriteDmaDescReqType) return slv;
179	   function toAxiWriteDmaDescReq (din : slv; valid : sl) return AxiWriteDmaDescReqType;
180	
181	
182	   -------------------------------------
183	   -- DMA Write Descriptor Ack (AxiStreamDmaV2)
184	   -- Returned to dma write engine in response to
185	   -- AxiWriteDescReqType.
186	   -------------------------------------
187	
188	   type AxiWriteDmaDescAckType is record
189	      valid      : sl;
190	      address    : slv(63 downto 0);
191	      metaEnable : sl;
192	      metaAddr   : slv(63 downto 0);
193	      dropEn     : sl;
194	      maxSize    : slv(31 downto 0);
195	      contEn     : sl;
196	      buffId     : slv(31 downto 0);
197	      timeout    : slv(31 downto 0);
198	   end record;
199	
200	   constant AXI_WRITE_DMA_DESC_ACK_INIT_C : AxiWriteDmaDescAckType := (
201	      valid      => '0',
202	      address    => (others => '0'),
203	      metaEnable => '0',
204	      metaAddr   => (others => '0'),
205	      dropEn     => '0',
206	      maxSize    => (others => '0'),
207	      contEn     => '0',
208	      buffId     => (others => '0'),
209	      timeout    => x"0000FFFF"
210	      );
211	
212	   type AxiWriteDmaDescAckArray is array (natural range<>) of AxiWriteDmaDescAckType;
213	
214	   constant AXI_WRITE_DMA_DESC_ACK_SIZE_C : integer := 195;
215	
216	   function toSlv (r                  : AxiWriteDmaDescAckType) return slv;
217	   function toAxiWriteDmaDescAck (din : slv; valid : sl) return AxiWriteDmaDescAckType;
218	
219	   -------------------------------------
220	   -- DMA Write Descriptor Return (AxiStreamDmaV2)
221	   -- Returned from dma engine when frame is complete
222	   -------------------------------------
223	
224	   type AxiWriteDmaDescRetType is record
225	      valid     : sl;
226	      buffId    : slv(31 downto 0);
227	      firstUser : slv(7 downto 0);
228	      lastUser  : slv(7 downto 0);
229	      size      : slv(31 downto 0);
230	      continue  : sl;
231	      result    : slv(3 downto 0);
232	      dest      : slv(7 downto 0);
233	      id        : slv(7 downto 0);      -- TID
234	   end record;
235	
236	   constant AXI_WRITE_DMA_DESC_RET_INIT_C : AxiWriteDmaDescRetType := (
237	      valid     => '0',
238	      buffId    => (others => '0'),
239	      firstUser => (others => '0'),
240	      lastUser  => (others => '0'),
241	      size      => (others => '0'),
242	      continue  => '0',
243	      result    => (others => '0'),
244	      dest      => (others => '0'),
245	      id        => (others => '0')
246	      );
247	
248	   type AxiWriteDmaDescRetArray is array (natural range<>) of AxiWriteDmaDescRetType;
249	
250	   constant AXI_WRITE_DMA_DESC_RET_SIZE_C : integer := 100;
251	
252	   function toSlv (r                  : AxiWriteDmaDescRetType) return slv;
253	   function toAxiWriteDmaDescRet (din : slv; valid : sl) return AxiWriteDmaDescRetType;
254	
255	   -------------------------------------
256	   -- DMA Write Tracking (AxiStreamDmaV2)
257	   -- Memory entry for tracking an in progress transaction.
258	   -------------------------------------
259	
260	   type AxiWriteDmaTrackType is record
261	      dest       : slv(7 downto 0);
262	      inUse      : sl;
263	      address    : slv(63 downto 0);
264	      metaEnable : sl;
265	      metaAddr   : slv(63 downto 0);
266	      maxSize    : slv(31 downto 0);
267	      size       : slv(31 downto 0);
268	      firstUser  : slv(7 downto 0);
269	      contEn     : sl;
270	      dropEn     : sl;
271	      id         : slv(7 downto 0);     -- TID
272	      buffId     : slv(31 downto 0);
273	      overflow   : sl;
274	      timeout    : slv(31 downto 0);
275	   end record;
276	
277	   constant AXI_WRITE_DMA_TRACK_INIT_C : AxiWriteDmaTrackType := (
278	      dest       => (others => '0'),
279	      inUse      => '0',
280	      address    => (others => '0'),
281	      metaEnable => '0',
282	      metaAddr   => (others => '0'),
283	      maxSize    => (others => '0'),
284	      size       => (others => '0'),
285	      firstUser  => (others => '0'),
286	      contEn     => '0',
287	      dropEn     => '0',
288	      id         => (others => '0'),
289	      buffId     => (others => '0'),
290	      overflow   => '0',
291	      timeout    => x"0000FFFF"
292	      );
293	
294	   type AxiWriteDmaTrackArray is array (natural range<>) of AxiWriteDmaTrackType;
295	
296	   constant AXI_WRITE_DMA_TRACK_SIZE_C : integer := 253;
297	
298	   function toSlv (r                : AxiWriteDmaTrackType) return slv;
299	   function toAxiWriteDmaTrack (din : slv) return AxiWriteDmaTrackType;
300	
301	   -------------------------------------
302	   -- DMA Read Descriptor Request (AxiStreamDmaV2)
303	   -- Passed to DMA engine to initiate a read.
304	   -------------------------------------
305	
306	   type AxiReadDmaDescReqType is record
307	      valid     : sl;
308	      address   : slv(63 downto 0);
309	      buffId    : slv(31 downto 0);
310	      firstUser : slv(7 downto 0);
311	      lastUser  : slv(7 downto 0);
312	      size      : slv(31 downto 0);
313	      continue  : sl;
314	      id        : slv(7 downto 0);
315	      dest      : slv(7 downto 0);
316	   end record;
317	
318	   constant AXI_READ_DMA_DESC_REQ_INIT_C : AxiReadDmaDescReqType := (
319	      valid     => '0',
320	      address   => (others => '0'),
321	      buffId    => (others => '0'),
322	      firstUser => (others => '0'),
323	      lastUser  => (others => '0'),
324	      size      => (others => '0'),
325	      continue  => '0',
326	      id        => (others => '0'),     -- TID
327	      dest      => (others => '0')
328	      );
329	
330	   type AxiReadDmaDescReqArray is array (natural range<>) of AxiReadDmaDescReqType;
331	
332	   constant AXI_READ_DMA_DESC_REQ_SIZE_C : integer := 161;
333	
334	   function toSlv (r                 : AxiReadDmaDescReqType) return slv;
335	   function toAxiReadDmaDescReq (din : slv; valid : sl) return AxiReadDmaDescReqType;
336	
337	   -------------------------------------
338	   -- DMA Read Descriptor Return (AxiStreamDmaV2)
339	   -- Returned from dma engine when frame is complete
340	   -------------------------------------
341	
342	   type AxiReadDmaDescRetType is record
343	      valid  : sl;
344	      buffId : slv(31 downto 0);
345	      result : slv(2 downto 0);
346	   end record;
347	
348	   constant AXI_READ_DMA_DESC_RET_INIT_C : AxiReadDmaDescRetType := (
349	      valid  => '0',
350	      buffId => (others => '0'),
351	      result => (others => '0')
352	      );
353	
354	   type AxiReadDmaDescRetArray is array (natural range<>) of AxiReadDmaDescRetType;
355	
356	   constant AXI_READ_DMA_DESC_RET_SIZE_C : integer := 35;
357	
358	   function toSlv (r                 : AxiReadDmaDescRetType) return slv;
359	   function toAxiReadDmaDescRet (din : slv; valid : sl) return AxiReadDmaDescRetType;
360	
361	end package AxiDmaPkg;
362	
363	package body AxiDmaPkg is
364	
365	   function toSlv (r : AxiReadDmaReqType) return slv is
366	      variable retValue : slv(AXI_READ_DMA_READ_REQ_SIZE_C-1 downto 0) := (others => '0');
367	      variable i        : integer                                      := 0;
368	   begin
369	      assignSlv(i, retValue, r.address);
370	      assignSlv(i, retValue, r.size);
371	      assignSlv(i, retValue, r.firstUser);
372	      assignSlv(i, retValue, r.lastUser);
373	      assignSlv(i, retValue, r.dest);
374	      assignSlv(i, retValue, r.id);
375	      assignSlv(i, retValue, r.prot);
376	      return(retValue);
377	   end function;
378	
379	   function toAxiReadDmaReq (din : slv; valid : sl) return AxiReadDmaReqType is
380	      variable desc : AxiReadDmaReqType := AXI_READ_DMA_REQ_INIT_C;
381	      variable i    : integer           := 0;
382	   begin
383	      desc.request := valid;
384	      assignRecord(i, din, desc.address);
385	      assignRecord(i, din, desc.size);
386	      assignRecord(i, din, desc.firstUser);
387	      assignRecord(i, din, desc.lastUser);
388	      assignRecord(i, din, desc.dest);
389	      assignRecord(i, din, desc.id);
390	      assignRecord(i, din, desc.prot);
391	      return(desc);
392	   end function;
393	
394	   function toSlv (r : AxiWriteDmaDescReqType) return slv is
395	      variable retValue : slv(AXI_WRITE_DMA_DESC_REQ_SIZE_C-1 downto 0) := (others => '0');
396	      variable i        : integer                                       := 0;
397	   begin
398	      assignSlv(i, retValue, r.dest);
399	      assignSlv(i, retValue, r.id);
400	      return(retValue);
401	   end function;
402	
403	   function toAxiWriteDmaDescReq (din : slv; valid : sl) return AxiWriteDmaDescReqType is
404	      variable desc : AxiWriteDmaDescReqType := AXI_WRITE_DMA_DESC_REQ_INIT_C;
405	      variable i    : integer                := 0;
406	   begin
407	      desc.valid := valid;
408	      assignRecord(i, din, desc.dest);
409	      assignRecord(i, din, desc.id);
410	      return(desc);
411	   end function;
412	
413	   function toSlv (r : AxiWriteDmaDescAckType) return slv is
414	      variable retValue : slv(AXI_WRITE_DMA_DESC_ACK_SIZE_C-1 downto 0) := (others => '0');
415	      variable i        : integer                                       := 0;
416	   begin
417	      assignSlv(i, retValue, r.address);
418	      assignSlv(i, retValue, r.dropEn);
419	      assignSlv(i, retValue, r.maxSize);
420	      assignSlv(i, retValue, r.contEn);
421	      assignSlv(i, retValue, r.buffId);
422	      assignSlv(i, retValue, r.metaEnable);
423	      assignSlv(i, retValue, r.metaAddr);
424	      return(retValue);
425	   end function;
426	
427	   function toAxiWriteDmaDescAck (din : slv; valid : sl) return AxiWriteDmaDescAckType is
428	      variable desc : AxiWriteDmaDescAckType := AXI_WRITE_DMA_DESC_ACK_INIT_C;
429	      variable i    : integer                := 0;
430	   begin
431	      desc.valid := valid;
432	      assignRecord(i, din, desc.address);
433	      assignRecord(i, din, desc.dropEn);
434	      assignRecord(i, din, desc.maxSize);
435	      assignRecord(i, din, desc.contEn);
436	      assignRecord(i, din, desc.buffId);
437	      assignRecord(i, din, desc.metaEnable);
438	      assignRecord(i, din, desc.metaAddr);
439	      return(desc);
440	   end function;
441	
442	   function toSlv (r : AxiWriteDmaDescRetType) return slv is
443	      variable retValue : slv(AXI_WRITE_DMA_DESC_RET_SIZE_C-1 downto 0) := (others => '0');
444	      variable i        : integer                                       := 0;
445	   begin
446	      assignSlv(i, retValue, r.buffId);
447	      assignSlv(i, retValue, r.firstUser);
448	      assignSlv(i, retValue, r.lastUser);
449	      assignSlv(i, retValue, r.size);
450	      assignSlv(i, retValue, r.continue);
451	      assignSlv(i, retValue, r.result);
452	      assignSlv(i, retValue, r.dest);
453	      assignSlv(i, retValue, r.id);
454	      return(retValue);
455	   end function;
456	
457	   function toAxiWriteDmaDescRet (din : slv; valid : sl) return AxiWriteDmaDescRetType is
458	      variable desc : AxiWriteDmaDescRetType := AXI_WRITE_DMA_DESC_RET_INIT_C;
459	      variable i    : integer                := 0;
460	   begin
461	      desc.valid := valid;
462	      assignRecord(i, din, desc.buffId);
463	      assignRecord(i, din, desc.firstUser);
464	      assignRecord(i, din, desc.lastUser);
465	      assignRecord(i, din, desc.size);
466	      assignRecord(i, din, desc.continue);
467	      assignRecord(i, din, desc.result);
468	      assignRecord(i, din, desc.dest);
469	      assignRecord(i, din, desc.id);
470	      return(desc);
471	   end function;
472	
473	   function toSlv (r : AxiWriteDmaTrackType) return slv is
474	      variable retValue : slv(AXI_WRITE_DMA_TRACK_SIZE_C-1 downto 0) := (others => '0');
475	      variable i        : integer                                    := 0;
476	   begin
477	      assignSlv(i, retValue, r.dest);
478	      assignSlv(i, retValue, r.inUse);
479	      assignSlv(i, retValue, r.address);
480	      assignSlv(i, retValue, r.metaEnable);
481	      assignSlv(i, retValue, r.metaAddr);
482	      assignSlv(i, retValue, r.maxSize);
483	      assignSlv(i, retValue, r.size);
484	      assignSlv(i, retValue, r.firstUser);
485	      assignSlv(i, retValue, r.contEn);
486	      assignSlv(i, retValue, r.dropEn);
487	      assignSlv(i, retValue, r.id);
488	      assignSlv(i, retValue, r.buffId);
489	      assignSlv(i, retValue, r.overflow);
490	      return(retValue);
491	   end function;
492	
493	   function toAxiWriteDmaTrack (din : slv) return AxiWriteDmaTrackType is
494	      variable desc : AxiWriteDmaTrackType := AXI_WRITE_DMA_TRACK_INIT_C;
495	      variable i    : integer              := 0;
496	   begin
497	      assignRecord(i, din, desc.dest);
498	      assignRecord(i, din, desc.inUse);
499	      assignRecord(i, din, desc.address);
500	      assignRecord(i, din, desc.metaEnable);
501	      assignRecord(i, din, desc.metaAddr);
502	      assignRecord(i, din, desc.maxSize);
503	      assignRecord(i, din, desc.size);
504	      assignRecord(i, din, desc.firstUser);
505	      assignRecord(i, din, desc.contEn);
506	      assignRecord(i, din, desc.dropEn);
507	      assignRecord(i, din, desc.id);
508	      assignRecord(i, din, desc.buffId);
509	      assignRecord(i, din, desc.overflow);
510	      return(desc);
511	   end function;
512	
513	   function toSlv (r : AxiReadDmaDescReqType) return slv is
514	      variable retValue : slv(AXI_READ_DMA_DESC_REQ_SIZE_C-1 downto 0) := (others => '0');
515	      variable i        : integer                                      := 0;
516	   begin
517	      assignSlv(i, retValue, r.address);
518	      assignSlv(i, retValue, r.buffId);
519	      assignSlv(i, retValue, r.firstUser);
520	      assignSlv(i, retValue, r.lastUser);
521	      assignSlv(i, retValue, r.size);
522	      assignSlv(i, retValue, r.continue);
523	      assignSlv(i, retValue, r.id);
524	      assignSlv(i, retValue, r.dest);
525	      return(retValue);
526	   end function;
527	
528	   function toAxiReadDmaDescReq (din : slv; valid : sl) return AxiReadDmaDescReqType is
529	      variable desc : AxiReadDmaDescReqType := AXI_READ_DMA_DESC_REQ_INIT_C;
530	      variable i    : integer               := 0;
531	   begin
532	      desc.valid := valid;
533	      assignRecord(i, din, desc.address);
534	      assignRecord(i, din, desc.buffId);
535	      assignRecord(i, din, desc.firstUser);
536	      assignRecord(i, din, desc.lastUser);
537	      assignRecord(i, din, desc.size);
538	      assignRecord(i, din, desc.continue);
539	      assignRecord(i, din, desc.id);
540	      assignRecord(i, din, desc.dest);
541	      return(desc);
542	   end function;
543	
544	   function toSlv (r : AxiReadDmaDescRetType) return slv is
545	      variable retValue : slv(AXI_READ_DMA_DESC_RET_SIZE_C-1 downto 0) := (others => '0');
546	      variable i        : integer                                      := 0;
547	   begin
548	      assignSlv(i, retValue, r.buffId);
549	      assignSlv(i, retValue, r.result);
550	      return(retValue);
551	   end function;
552	
553	   function toAxiReadDmaDescRet (din : slv; valid : sl) return AxiReadDmaDescRetType is
554	      variable desc : AxiReadDmaDescRetType := AXI_READ_DMA_DESC_RET_INIT_C;
555	      variable i    : integer               := 0;
556	   begin
557	      desc.valid := valid;
558	      assignRecord(i, din, desc.buffId);
559	      assignRecord(i, din, desc.result);
560	      return(desc);
561	   end function;
562	
563	end package body AxiDmaPkg;
564	
