16	library ieee;
17	use ieee.std_logic_1164.all;
18	use ieee.std_logic_arith.all;
19	use ieee.std_logic_unsigned.all;
20	
21	
22	library surf;
23	use surf.StdRtlPkg.all;
24	use surf.AxiStreamPkg.all;
25	use surf.AxiLitePkg.all;
26	use surf.AxiPkg.all;
27	use surf.AxiDmaPkg.all;
28	
29	entity AxiStreamDmaV2 is
30	   generic (
31	      TPD_G              : time                     := 1 ns;
32	      SIMULATION_G       : boolean                  := false;
33	      DESC_AWIDTH_G      : positive range 4 to 12   := 12;
34	      DESC_ARB_G         : boolean                  := true;
35	      DESC_SYNTH_MODE_G  : string                   := "inferred";
36	      DESC_MEMORY_TYPE_G : string                   := "block";
37	      AXIL_BASE_ADDR_G   : slv(31 downto 0)         := x"00000000";
38	      AXI_READY_EN_G     : boolean                  := false;
39	      AXIS_READY_EN_G    : boolean                  := false;
40	      AXIS_CONFIG_G      : AxiStreamConfigType;
41	      AXI_DMA_CONFIG_G   : AxiConfigType;
42	      CHAN_COUNT_G       : positive range 1 to 16   := 1;
43	      BURST_BYTES_G      : positive range 1 to 4096 := 4096;
44	      WR_PIPE_STAGES_G   : natural                  := 1;
45	      RD_PIPE_STAGES_G   : natural                  := 1;
46	      RD_PEND_THRESH_G   : positive                 := 1);  -- In units of bytes
47	   port (
48	      -- Clock/Reset
49	      axiClk          : in  sl;
50	      axiRst          : in  sl;
51	      -- Register Access & Interrupt
52	      axilReadMaster  : in  AxiLiteReadMasterType;
53	      axilReadSlave   : out AxiLiteReadSlaveType;
54	      axilWriteMaster : in  AxiLiteWriteMasterType;
55	      axilWriteSlave  : out AxiLiteWriteSlaveType;
56	      interrupt       : out sl;
57	      online          : out slv(CHAN_COUNT_G-1 downto 0);
58	      acknowledge     : out slv(CHAN_COUNT_G-1 downto 0);
59	      buffGrpPause    : out slv(7 downto 0);
60	      -- AXI Stream Interface
61	      sAxisMasters    : in  AxiStreamMasterArray(CHAN_COUNT_G-1 downto 0);
62	      sAxisSlaves     : out AxiStreamSlaveArray(CHAN_COUNT_G-1 downto 0);
63	      mAxisMasters    : out AxiStreamMasterArray(CHAN_COUNT_G-1 downto 0);
64	      mAxisSlaves     : in  AxiStreamSlaveArray(CHAN_COUNT_G-1 downto 0);
65	      mAxisCtrl       : in  AxiStreamCtrlArray(CHAN_COUNT_G-1 downto 0);
66	      -- AXI Interfaces, 0 = Desc, 1-CHAN_COUNT_G = DMA
67	      axiReadMasters  : out AxiReadMasterArray(CHAN_COUNT_G downto 0);
68	      axiReadSlaves   : in  AxiReadSlaveArray(CHAN_COUNT_G downto 0);
69	      axiWriteMasters : out AxiWriteMasterArray(CHAN_COUNT_G downto 0);
70	      axiWriteSlaves  : in  AxiWriteSlaveArray(CHAN_COUNT_G downto 0);
71	      axiWriteCtrl    : in  AxiCtrlArray(CHAN_COUNT_G downto 0));
72	end AxiStreamDmaV2;
73	
74	architecture structure of AxiStreamDmaV2 is
75	
76	   signal dmaWrDescReq    : AxiWriteDmaDescReqArray(CHAN_COUNT_G-1 downto 0);
77	   signal dmaWrDescAck    : AxiWriteDmaDescAckArray(CHAN_COUNT_G-1 downto 0);
78	   signal dmaWrDescRet    : AxiWriteDmaDescRetArray(CHAN_COUNT_G-1 downto 0);
79	   signal dmaWrDescRetAck : slv(CHAN_COUNT_G-1 downto 0);
80	
81	   signal dmaRdDescReq    : AxiReadDmaDescReqArray(CHAN_COUNT_G-1 downto 0);
82	   signal dmaRdDescAck    : slv(CHAN_COUNT_G-1 downto 0);
83	   signal dmaRdDescRet    : AxiReadDmaDescRetArray(CHAN_COUNT_G-1 downto 0);
84	   signal dmaRdDescRetAck : slv(CHAN_COUNT_G-1 downto 0);
85	
86	   signal descWriteMasters : AxiWriteMasterArray(CHAN_COUNT_G-1 downto 0);
87	   signal descWriteSlaves  : AxiWriteSlaveArray(CHAN_COUNT_G-1 downto 0);
88	
89	   signal dataWriteMasters : AxiWriteMasterArray(CHAN_COUNT_G-1 downto 0);
90	   signal dataWriteSlaves  : AxiWriteSlaveArray(CHAN_COUNT_G-1 downto 0);
91	   signal dataWriteCtrl    : AxiCtrlArray(CHAN_COUNT_G-1 downto 0);
92	
93	   signal axiRdCache : slv(3 downto 0);
94	   signal axiWrCache : slv(3 downto 0);
95	
96	   signal axiReset : slv(CHAN_COUNT_G-1 downto 0);
97	
98	   attribute dont_touch             : string;
99	   attribute dont_touch of axiReset : signal is "true";
100	
101	begin
102	
103	   assert (AXI_DMA_CONFIG_G.DATA_BYTES_C >= 8)
104	      report "AxiPcieDma: AXI STREAM DMA must have a byte width of >= 8Bytes (64-bits)" severity failure;
105	
106	   assert (isPowerOf2(BURST_BYTES_G) = true)
107	      report "BURST_BYTES_G must be power of 2" severity failure;
108	
109	   U_DmaDesc : entity surf.AxiStreamDmaV2Desc
110	      generic map (
111	         TPD_G              => TPD_G,
112	         CHAN_COUNT_G       => CHAN_COUNT_G,
113	         AXIL_BASE_ADDR_G   => AXIL_BASE_ADDR_G,
114	         AXI_CONFIG_G       => AXI_DMA_CONFIG_G,
115	         DESC_AWIDTH_G      => DESC_AWIDTH_G,
116	         DESC_ARB_G         => DESC_ARB_G,
117	         DESC_SYNTH_MODE_G  => DESC_SYNTH_MODE_G,
118	         DESC_MEMORY_TYPE_G => DESC_MEMORY_TYPE_G)
119	      port map (
120	         -- Clock/Reset
121	         axiClk          => axiClk,
122	         axiRst          => axiRst,
123	         axilReadMaster  => axilReadMaster,
124	         axilReadSlave   => axilReadSlave,
125	         axilWriteMaster => axilWriteMaster,
126	         axilWriteSlave  => axilWriteSlave,
127	         interrupt       => interrupt,
128	         online          => online,
129	         acknowledge     => acknowledge,
130	         dmaWrDescReq    => dmaWrDescReq,
131	         dmaWrDescAck    => dmaWrDescAck,
132	         dmaWrDescRet    => dmaWrDescRet,
133	         dmaWrDescRetAck => dmaWrDescRetAck,
134	         dmaRdDescReq    => dmaRdDescReq,
135	         dmaRdDescAck    => dmaRdDescAck,
136	         dmaRdDescRet    => dmaRdDescRet,
137	         dmaRdDescRetAck => dmaRdDescRetAck,
138	         axiRdCache      => axiRdCache,
139	         axiWrCache      => axiWrCache,
140	         axiWriteMasters => descWriteMasters,
141	         axiWriteSlaves  => descWriteSlaves,
142	         buffGrpPause    => buffGrpPause);
143	
144	   -- Read/Write channel 0 unused.
145	   axiReadMasters(0)  <= AXI_READ_MASTER_INIT_C;
146	   axiWriteMasters(0) <= AXI_WRITE_MASTER_INIT_C;
147	
148	   U_ChanGen : for i in 0 to CHAN_COUNT_G-1 generate
149	
150	      -- Help with timing
151	      U_AxisRst : entity surf.RstPipeline
152	         generic map (
153	            TPD_G     => TPD_G,
154	            INV_RST_G => false)
155	         port map (
156	            clk    => axiClk,
157	            rstIn  => axiRst,
158	            rstOut => axiReset(i));
159	
160	      U_DmaRead : entity surf.AxiStreamDmaV2Read
161	         generic map (
162	            TPD_G           => TPD_G,
163	            AXIS_READY_EN_G => AXIS_READY_EN_G,
164	            AXIS_CONFIG_G   => AXIS_CONFIG_G,
165	            AXI_CONFIG_G    => AXI_DMA_CONFIG_G,
166	            PIPE_STAGES_G   => RD_PIPE_STAGES_G,
167	            BURST_BYTES_G   => BURST_BYTES_G,
168	            PEND_THRESH_G   => RD_PEND_THRESH_G)
169	         port map (
170	            axiClk          => axiClk,
171	            axiRst          => axiReset(i),
172	            dmaRdDescReq    => dmaRdDescReq(i),
173	            dmaRdDescAck    => dmaRdDescAck(i),
174	            dmaRdDescRet    => dmaRdDescRet(i),
175	            dmaRdDescRetAck => dmaRdDescRetAck(i),
176	            dmaRdIdle       => open,
177	            axiCache        => axiRdCache,
178	            -- Streaming Interface
179	            axisMaster      => mAxisMasters(i),
180	            axisSlave       => mAxisSlaves(i),
181	            axisCtrl        => mAxisCtrl(i),
182	            axiReadMaster   => axiReadMasters(i+1),
183	            axiReadSlave    => axiReadSlaves(i+1));
184	
185	      U_DmaWrite : entity surf.AxiStreamDmaV2Write
186	         generic map (
187	            TPD_G             => TPD_G,
188	            AXI_READY_EN_G    => AXI_READY_EN_G,
189	            AXIS_CONFIG_G     => AXIS_CONFIG_G,
190	            AXI_CONFIG_G      => AXI_DMA_CONFIG_G,
191	            PIPE_STAGES_G     => WR_PIPE_STAGES_G,
192	            BURST_BYTES_G     => BURST_BYTES_G,
193	            ACK_WAIT_BVALID_G => false)
194	         port map (
195	            axiClk          => axiClk,
196	            axiRst          => axiReset(i),
197	            dmaWrDescReq    => dmaWrDescReq(i),
198	            dmaWrDescAck    => dmaWrDescAck(i),
199	            dmaWrDescRet    => dmaWrDescRet(i),
200	            dmaWrDescRetAck => dmaWrDescRetAck(i),
201	            dmaWrIdle       => open,
202	            axiCache        => axiWrCache,
203	            axisMaster      => sAxisMasters(i),
204	            axisSlave       => sAxisSlaves(i),
205	            axiWriteMaster  => dataWriteMasters(i),
206	            axiWriteSlave   => dataWriteSlaves(i),
207	            axiWriteCtrl    => dataWriteCtrl(i));
208	
209	      -----------------------------------------------------------------------------------------
210	      -- This MUX is used to make sure that the write descriptor is sent after the data is sent
211	      -----------------------------------------------------------------------------------------
212	      U_DmaWriteMux : entity surf.AxiStreamDmaV2WriteMux
213	         generic map (
214	            TPD_G             => TPD_G,
215	            AXI_CONFIG_G      => AXI_DMA_CONFIG_G,
216	            AXI_READY_EN_G    => AXI_READY_EN_G,
217	            ACK_WAIT_BVALID_G => false)
218	         port map (
