226	            -- DMA Descriptor Write Path
227	            descWriteMaster => descWriteMasters(i),
228	            descWriteSlave  => descWriteSlaves(i),
229	            -- MUX Write Path
230	            mAxiWriteMaster => axiWriteMasters(i+1),
