1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description:
5	-- Block to transfer a single AXI Stream frame into memory using an AXI
6	-- interface. Version 2 supports interleaved frames.
7	-------------------------------------------------------------------------------
8	-- This file is part of 'SLAC Firmware Standard Library'.
9	-- It is subject to the license terms in the LICENSE.txt file found in the
10	-- top-level directory of this distribution and at:
11	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
12	-- No part of 'SLAC Firmware Standard Library', including this file,
13	-- may be copied, modified, propagated, or distributed except according to
14	-- the terms contained in the LICENSE.txt file.
15	-------------------------------------------------------------------------------
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	use ieee.std_logic_arith.all;
20	use ieee.std_logic_unsigned.all;
21	
22	
23	library surf;
24	use surf.StdRtlPkg.all;
25	use surf.AxiStreamPkg.all;
26	use surf.AxiPkg.all;
27	use surf.AxiDmaPkg.all;
28	
29	entity AxiStreamDmaV2Write is
30	   generic (
31	      TPD_G             : time                    := 1 ns;
32	      AXI_READY_EN_G    : boolean                 := false;
33	      AXIS_CONFIG_G     : AxiStreamConfigType;
34	      AXI_CONFIG_G      : AxiConfigType;
35	      PIPE_STAGES_G     : natural                 := 1;
36	      BURST_BYTES_G     : integer range 1 to 4096 := 4096;
37	      ACK_WAIT_BVALID_G : boolean                 := true);
38	   port (
39	      -- Clock/Reset
40	      axiClk          : in  sl;
41	      axiRst          : in  sl;
42	      -- DMA write descriptor request, ack and return
43	      dmaWrDescReq    : out AxiWriteDmaDescReqType;
44	      dmaWrDescAck    : in  AxiWriteDmaDescAckType;
45	      dmaWrDescRet    : out AxiWriteDmaDescRetType;
46	      dmaWrDescRetAck : in  sl;
47	      -- Config and status
48	      dmaWrIdle       : out sl;
49	      axiCache        : in  slv(3 downto 0);
50	      -- Streaming Interface
51	      axisMaster      : in  AxiStreamMasterType;
52	      axisSlave       : out AxiStreamSlaveType;
53	      -- AXI Interface
54	      axiWriteMaster  : out AxiWriteMasterType;
55	      axiWriteSlave   : in  AxiWriteSlaveType;
56	      axiWriteCtrl    : in  AxiCtrlType := AXI_CTRL_UNUSED_C);
57	end AxiStreamDmaV2Write;
58	
59	architecture rtl of AxiStreamDmaV2Write is
60	
61	   constant DATA_BYTES_C      : integer := AXIS_CONFIG_G.TDATA_BYTES_C;
62	   constant ADDR_LSB_C        : integer := bitSize(DATA_BYTES_C-1);
63	   constant FIFO_ADDR_WIDTH_C : natural := (AXI_CONFIG_G.LEN_BITS_C+1);
64	
65	   type StateType is (
66	      RESET_S,
67	      INIT_S,
68	      IDLE_S,
69	      REQ_S,
70	      ADDR_S,
71	      MOVE_S,
72	      PAD_S,
73	      META_S,
74	      RETURN_S,
75	      DUMP_S);
76	
77	   type RegType is record
78	      dmaWrDescReq : AxiWriteDmaDescReqType;
79	      dmaWrTrack   : AxiWriteDmaTrackType;
80	      dmaWrDescRet : AxiWriteDmaDescRetType;
81	      result       : slv(1 downto 0);
82	      reqCount     : slv(31 downto 0);
83	      ackCount     : slv(31 downto 0);
84	      stCount      : slv(31 downto 0);
85	      timeoutCnt   : slv(31 downto 0);
86	      awlen        : slv(AXI_CONFIG_G.LEN_BITS_C-1 downto 0);
87	      axiLen       : AxiLenType;
88	      wMaster      : AxiWriteMasterType;
89	      slave        : AxiStreamSlaveType;
90	      state        : StateType;
91	      lastUser     : slv(7 downto 0);
92	      continue     : sl;
93	      dmaWrIdle    : sl;
94	   end record RegType;
95	
96	   constant REG_INIT_C : RegType := (
97	      dmaWrDescReq => AXI_WRITE_DMA_DESC_REQ_INIT_C,
98	      dmaWrTrack   => AXI_WRITE_DMA_TRACK_INIT_C,
99	      dmaWrDescRet => AXI_WRITE_DMA_DESC_RET_INIT_C,
100	      result       => (others => '0'),
101	      reqCount     => (others => '0'),
102	      ackCount     => (others => '0'),
103	      stCount      => (others => '0'),
104	      timeoutCnt   => (others => '0'),
105	      awlen        => (others => '0'),
106	      axiLen       => AXI_LEN_INIT_C,
107	      wMaster      => axiWriteMasterInit(AXI_CONFIG_G, '1', "01", "0000"),
108	      slave        => AXI_STREAM_SLAVE_INIT_C,
109	      state        => RESET_S,
110	      lastUser     => (others => '0'),
111	      continue     => '0',
112	      dmaWrIdle    => '0');
113	
114	   signal r             : RegType := REG_INIT_C;
115	   signal rin           : RegType;
116	   signal pause         : sl;
117	   signal intAxisMaster : AxiStreamMasterType;
118	   signal intAxisSlave  : AxiStreamSlaveType;
119	   signal trackDin      : slv(AXI_WRITE_DMA_TRACK_SIZE_C-1 downto 0);
120	   signal trackDout     : slv(AXI_WRITE_DMA_TRACK_SIZE_C-1 downto 0);
121	   signal trackData     : AxiWriteDmaTrackType;
122	
123	   -- attribute dont_touch      : string;
124	   -- attribute dont_touch of r : signal is "true";
125	
126	begin
127	
128	   assert AXIS_CONFIG_G.TDATA_BYTES_C = AXI_CONFIG_G.DATA_BYTES_C
129	      report "AXIS (" & integer'image(AXIS_CONFIG_G.TDATA_BYTES_C) & ") and AXI ("
130	      & integer'image(AXI_CONFIG_G.DATA_BYTES_C) & ") must have equal data widths" severity failure;
131	
132	   U_Pipeline : entity surf.AxiStreamPipeline
133	      generic map (
134	         TPD_G         => TPD_G,
135	         PIPE_STAGES_G => PIPE_STAGES_G)
136	      port map (
137	         axisClk     => axiClk,
138	         axisRst     => axiRst,
139	         sAxisMaster => axisMaster,
140	         sAxisSlave  => axisSlave,
141	         mAxisMaster => intAxisMaster,
142	         mAxisSlave  => intAxisSlave);
143	
144	   -- Pause when enabled
145	   pause <= '0' when (AXI_READY_EN_G) else axiWriteCtrl.pause;
146	
147	   -- State machine
148	   comb : process (axiCache, axiRst, axiWriteSlave, dmaWrDescAck,
149	                   dmaWrDescRetAck, intAxisMaster, pause, r, trackData) is
150	      variable v     : RegType;
151	      variable bytes : natural;
152	   begin
153	      -- Latch the current value
154	      v := r;
155	
156	      -- Clear stream slave
157	      v.slave.tReady := '0';
158	
159	      -- Cache setting
160	      v.wMaster.awcache := axiCache;
161	
162	      -- Reset AXI Signals
163	      if (axiWriteSlave.awready = '1') or (AXI_READY_EN_G = false) then
164	         v.wMaster.awvalid := '0';
165	      end if;
166	      if (axiWriteSlave.wready = '1') or (AXI_READY_EN_G = false) then
167	         v.wMaster.wvalid := '0';
168	         v.wMaster.wlast  := '0';
169	      end if;
170	
171	      -- Wait for memory bus response
172	      if (axiWriteSlave.bvalid = '1') and (ACK_WAIT_BVALID_G = true) then
173	         -- Increment the counter
174	         v.ackCount := r.ackCount + 1;
175	         -- Check for error response
176	         if (axiWriteSlave.bresp /= "00") and (r.result = 0) then
177	            -- Latch the response value
178	            v.result := axiWriteSlave.bresp;
179	         end if;
180	      end if;
181	
182	      -- Descriptor handshaking
183	      if dmaWrDescRetAck = '1' then
184	         v.dmaWrDescRet.valid := '0';
185	      end if;
186	      if dmaWrDescAck.valid = '1' then
187	         v.dmaWrDescReq.valid := '0';
188	      end if;
189	
190	      -- Count number of bytes in return data
191	      if (AXIS_CONFIG_G.TKEEP_MODE_C = TKEEP_COUNT_C) then
192	         bytes := conv_integer(intAxisMaster.tKeep(bitSize(AXI_STREAM_MAX_TKEEP_WIDTH_C)-1 downto 0));
193	      else
194	         bytes := getTKeep(intAxisMaster.tKeep(DATA_BYTES_C-1 downto 0), AXIS_CONFIG_G);
195	      end if;
196	
197	      -- State machine
198	      case r.state is
199	         ----------------------------------------------------------------------
200	         when RESET_S =>
201	            v := REG_INIT_C;
202	            if r.stCount = 100 then
203	               v.state := INIT_S;
204	            else
205	               v.stCount := r.stCount + 1;
206	            end if;
207	         ----------------------------------------------------------------------
208	         when INIT_S =>
209	            v.dmaWrTrack.dest := r.dmaWrTrack.dest + 1;
210	            if r.dmaWrTrack.dest = 255 then
211	               v.state := IDLE_S;
212	            end if;
213	         ----------------------------------------------------------------------
214	         when IDLE_S =>
215	            v.stCount           := (others => '0');
216	            -- Set write dma request data
217	            v.dmaWrDescReq.dest := intAxisMaster.tDest;
218	            v.dmaWrDescReq.id   := intAxisMaster.tId;
219	
220	            if intAxisMaster.tValid = '1' then
221	               -- Current destination matches incoming frame
222	               if r.dmaWrTrack.dest = intAxisMaster.tDest then
223	
224	                  -- Frame is still in progress
225	                  if r.dmaWrTrack.inUse = '1' then
226	                     if r.dmaWrTrack.dropEn = '1' then
227	                        -- Next state
228	                        v.state := DUMP_S;
229	                     else
230	                        -- Next state
231	                        v.state := ADDR_S;
232	                     end if;
233	
234	                  -- New frame with same destination, new descriptor
235	                  else
236	                     v.dmaWrDescReq.valid := '1';
237	                     v.state              := REQ_S;
238	                  end if;
239	
240	               -- Wait for mem selection to match incoming frame
241	               elsif trackData.dest = intAxisMaster.tDest then
242	                  -- Set tracking data
243	                  v.dmaWrTrack := trackData;
244	
245	                  -- Is entry valid or do we need a new buffer
246	                  if trackData.inUse = '1' then
247	                     if trackData.dropEn = '1' then
248	                        -- Next state
249	                        v.state := DUMP_S;
250	                     else
251	                        -- Next state
252	                        v.state := ADDR_S;
253	                     end if;
254	                  else
255	                     -- Request a new descriptor
256	                     v.dmaWrDescReq.valid := '1';
257	                     -- Next state
258	                     v.state              := REQ_S;
259	                  end if;
260	               end if;
261	            end if;
262	         ----------------------------------------------------------------------
263	         when REQ_S =>
264	            -- Wait for response and latch fields
265	            if dmaWrDescAck.valid = '1' then
266	               v.dmaWrTrack.inUse      := '1';
267	               v.dmaWrTrack.size       := (others => '0');
268	               v.dmaWrTrack.firstUser  := (others => '0');
269	               v.dmaWrTrack.contEn     := dmaWrDescAck.contEn;
270	               v.dmaWrTrack.dropEn     := dmaWrDescAck.dropEn;
271	               v.dmaWrTrack.buffId     := dmaWrDescAck.buffId;
272	               v.dmaWrTrack.overflow   := '0';
273	               v.dmaWrTrack.metaEnable := dmaWrDescAck.metaEnable;
274	               v.dmaWrTrack.metaAddr   := dmaWrDescAck.metaAddr;
275	               v.dmaWrTrack.address    := dmaWrDescAck.address;
276	               v.dmaWrTrack.maxSize    := dmaWrDescAck.maxSize;
277	               v.dmaWrTrack.timeout    := dmaWrDescAck.timeout;
278	
279	               -- Descriptor return calls for dumping frame?
280	               if dmaWrDescAck.dropEn = '1' then
281	                  -- Next state
282	                  v.state := DUMP_S;
283	               else
284	                  -- Next state
285	                  v.state := ADDR_S;
286	               end if;
287	            end if;
288	         ----------------------------------------------------------------------
289	         when ADDR_S =>
290	            -- Reset continue and last user
291	            v.continue := '0';
292	            v.lastUser := (others => '0');
293	            -- Determine transfer size aligned to 4k boundaries
294	            getAxiLenProc(AXI_CONFIG_G, BURST_BYTES_G, r.dmaWrTrack.maxSize, r.dmaWrTrack.address, r.axiLen, v.axiLen);
295	            -- Address can be sent
296	            if (v.wMaster.awvalid = '0') and (v.axiLen.valid = "11") then
297	               -- Set the memory address
298	               v.wMaster.awaddr(AXI_CONFIG_G.ADDR_WIDTH_C-1 downto 0) :=
299	                  r.dmaWrTrack.address(AXI_CONFIG_G.ADDR_WIDTH_C-1 downto 0);
300	               -- Latch AXI awlen value
301	               v.wMaster.awlen := v.axiLen.value;
302	               v.awlen         := v.axiLen.value(AXI_CONFIG_G.LEN_BITS_C-1 downto 0);
303	               -- Check if enough room
304	               if pause = '0' then
305	                  -- Set the flag
306	                  v.wMaster.awvalid := '1';
307	                  v.axiLen.valid    := "00";
308	                  -- Increment the counter
309	                  v.reqCount        := r.reqCount + 1;
310	                  -- Next state
311	                  v.state           := MOVE_S;
312	               end if;
313	            end if;
314	         ----------------------------------------------------------------------
315	         when MOVE_S =>
316	            -- Incoming valid data
317	            if intAxisMaster.tValid = '1' then
318	               v.stCount := (others => '0');
319	               -- Destination has changed, complete current write
320	               if intAxisMaster.tDest /= r.dmaWrTrack.dest then
321	                  v.state := PAD_S;
322	               -- Overflow detect
323	               elsif (r.dmaWrTrack.maxSize(31 downto log2(DATA_BYTES_C)) = 0) then
324	                  -- Multi-descriptor DMA is supported
325	                  if r.dmaWrTrack.contEn = '1' then
326	                     v.continue         := '1';
327	                     v.dmaWrTrack.inUse := '0';
328	                  else
329	                     v.dmaWrTrack.overflow := '1';
330	                     v.dmaWrTrack.dropEn   := '1';
331	                  end if;
332	                  -- Pad current write, dump of incoming frame will occur
333	                  -- after state machine returns to idle due to dropEn being set.
334	                  -- Return will follow pad with inUse = '0'
335	                  v.state := PAD_S;
336	               -- We are able to push more data
337	               elsif v.wMaster.wvalid = '0' then
338	                  -- Accept the data
339	                  v.slave.tReady                               := '1';
340	                  -- Move the data
341	                  v.wMaster.wvalid                             := '1';
342	                  v.wMaster.wdata((DATA_BYTES_C*8)-1 downto 0) := intAxisMaster.tData((DATA_BYTES_C*8)-1 downto 0);
343	                  -- Set byte write strobes
344	                  if (AXIS_CONFIG_G.TKEEP_MODE_C = TKEEP_COUNT_C) then
345	                     v.wMaster.wstrb(AXI_STREAM_MAX_TKEEP_WIDTH_C-1 downto 0) := genTKeep(bytes);
346	                  else
347	                     v.wMaster.wstrb(DATA_BYTES_C-1 downto 0) := intAxisMaster.tKeep(DATA_BYTES_C-1 downto 0);
348	                  end if;
349	                  -- Address and size increment
350	                  v.dmaWrTrack.address := r.dmaWrTrack.address + DATA_BYTES_C;
351	                  -- Force address alignment
352	                  if (DATA_BYTES_C > 1) then
353	                     v.dmaWrTrack.address(ADDR_LSB_C-1 downto 0) := (others => '0');
354	                  end if;
355	                  -- Increment the byte counter
356	                  v.dmaWrTrack.size    := r.dmaWrTrack.size + bytes;
357	                  v.dmaWrTrack.maxSize := r.dmaWrTrack.maxSize - bytes;
358	                  -- First word
359	                  if r.dmaWrTrack.size = 0 then
360	                     -- Latch the tDest/tId/tUser values
361	                     v.dmaWrTrack.id := intAxisMaster.tId;
362	                     v.dmaWrTrack.firstUser(AXIS_CONFIG_G.TUSER_BITS_C-1 downto 0) :=
363	                        axiStreamGetUserField(AXIS_CONFIG_G, intAxisMaster, 0);
364	                  end if;
365	                  -- Check for last AXIS word
366	                  if intAxisMaster.tLast = '1' then
367	                     -- Latch the tUser value
368	                     v.lastUser(AXIS_CONFIG_G.TUSER_BITS_C-1 downto 0) :=
369	                        axiStreamGetUserField(AXIS_CONFIG_G, intAxisMaster);
370	                     v.dmaWrTrack.inUse := '0';
371	                     -- Pad write if transaction is not done, return will following PAD because inUse = 0
372	                     if r.awlen = 0 then
373	                        if r.dmaWrTrack.metaEnable = '1' then
374	                           v.state := META_S;
375	                        else
376	                           v.state := RETURN_S;
377	                        end if;
378	                     else
379	                        v.state := PAD_S;
380	                     end if;
381	                  end if;
382	                  -- Check for last AXI transfer
383	                  if r.awlen = 0 then
384	                     -- Set the flag
385	                     v.wMaster.wlast := '1';
386	                     -- If next state has not already been updated, decide where
387	                     -- to go next.
388	                     if v.state = MOVE_S then
389	                        -- If this burst exactly filled the buffer while the
390	                        -- frame continues, start the continue here (return the
391	                        -- descriptor with continue set) rather than re-entering
392	                        -- ADDR_S.  Re-entering ADDR_S with maxSize=0 would issue
393	                        -- a stray zero-length burst at the next buffer's base
394	                        -- address; on a host DMA that off-by-one write lands
395	                        -- past the mapped page and raises an IOMMU page fault.
396	                        -- (contEn=0 keeps the legacy overflow/drop path.)
397	                        if (v.dmaWrTrack.maxSize(31 downto log2(DATA_BYTES_C)) = 0) and (r.dmaWrTrack.contEn = '1') then
398	                           v.continue         := '1';
399	                           v.dmaWrTrack.inUse := '0';
400	                           if r.dmaWrTrack.metaEnable = '1' then
401	                              v.state := META_S;
402	                           else
403	                              v.state := RETURN_S;
404	                           end if;
405	                        else
406	                           v.state := IDLE_S;
407	                        end if;
408	                     end if;
409	                  else
410	                     -- Decrement the transaction counter
411	                     v.awlen := r.awlen - 1;
412	                  end if;
413	               end if;
414	            -- If the incoming AXI stream data stalled out ('timeout event') while we are in the
415	            -- middle of a write, we treat it like a destination change and complete the write
416	            -- with the valid strobes as '0' and re-start it when data is available
417	            elsif r.stCount = 100 then
418	               v.state := PAD_S;
419	            else
420	               v.stCount := r.stCount + 1;
421	            end if;
422	         ----------------------------------------------------------------------
423	         when PAD_S =>
424	            v.stCount := (others => '0');
425	            -- We are able to push more data
426	            if v.wMaster.wvalid = '0' then
427	               v.wMaster.wvalid := '1';
428	               v.wMaster.wstrb  := (others => '0');
429	               -- Check for last AXI transfer
430	               if r.awlen = 0 then
431	                  -- Set the flag
432	                  v.wMaster.wlast := '1';
433	                  -- Frame is done. Go to return. Otherwise go to idle.
434	                  if r.dmaWrTrack.inUse = '0' then
435	                     if r.dmaWrTrack.metaEnable = '1' then
436	                        v.state := META_S;
437	                     else
438	                        v.state := RETURN_S;
439	                     end if;
440	                  else
441	                     v.state := IDLE_S;
442	                  end if;
443	               else
444	                  -- Decrement the counter
445	                  v.awlen := r.awlen - 1;
446	               end if;
447	            end if;
448	         ----------------------------------------------------------------------
449	         when META_S =>
450	            -- Wait for existing transactions to complete
451	            if (v.wMaster.wvalid = '0') and (v.wMaster.awvalid = '0') then
452	
453	               -- Write address channel
454	               v.wMaster.awvalid := '1';
455	               v.wMaster.awaddr  := r.dmaWrTrack.metaAddr;
456	               v.wMaster.awlen   := x"00";  -- Single transaction
457	
458	               -- Write data channel
459	               v.wMaster.wvalid              := '1';
460	               v.wMaster.wlast               := '1';
461	               v.wMaster.wstrb               := resize(x"FF", AXI_MAX_WSTRB_WIDTH_C);  -- Descriptor data, 64-bits
462	               v.wMaster.wdata(63 downto 32) := r.dmaWrTrack.size;
463	               v.wMaster.wdata(31 downto 24) := r.dmaWrTrack.firstUser;
464	               v.wMaster.wdata(23 downto 16) := r.lastUser;
465	               v.wMaster.wdata(15 downto 4)  := (others => '0');
466	               v.wMaster.wdata(3)            := r.continue;
467	               v.wMaster.wdata(2)            := r.dmaWrTrack.overflow;
468	               v.wMaster.wdata(1 downto 0)   := r.result;
469	
470	               -- Increment the counter
471	               v.reqCount := r.reqCount + 1;
472	
473	               -- Next state
474	               v.state := RETURN_S;
475	            end if;
476	         ----------------------------------------------------------------------
477	         when RETURN_S =>
478	            -- Previous return was acked
479	            if v.dmaWrDescRet.valid = '0' then
480	               -- Setup return record
481	               v.dmaWrDescRet.buffId             := r.dmaWrTrack.buffId;
482	               v.dmaWrDescRet.firstUser          := r.dmaWrTrack.firstUser;
483	               v.dmaWrDescRet.size               := r.dmaWrTrack.size;
484	               v.dmaWrDescRet.dest               := r.dmaWrTrack.dest;
485	               v.dmaWrDescRet.id                 := r.dmaWrTrack.id;
486	               v.dmaWrDescRet.lastUser           := r.lastUser;
487	               v.dmaWrDescRet.continue           := r.continue;
488	               v.dmaWrDescRet.result(3)          := '0';
489	               v.dmaWrDescRet.result(2)          := r.dmaWrTrack.overflow;
490	               v.dmaWrDescRet.result(1 downto 0) := r.result;
491	               -- Init record
492	               v.dmaWrTrack.inUse                := '0';
493	               -- Wait for all transactions to complete before returning descriptor
494	               if (r.ackCount = r.reqCount) or (ACK_WAIT_BVALID_G = false) then
495	                  v.dmaWrDescRet.valid := '1';
496	                  v.state              := IDLE_S;
497	               -- Check for ACK timeout
498	               elsif (r.stCount = r.dmaWrTrack.timeout) then
499	                  -- Latch the errors flags
500	                  v.dmaWrDescRet.result(1 downto 0) := "11";
501	                  v.dmaWrDescRet.result(3)          := '1';
502	               else
503	                  -- Increment the counter
504	                  v.stCount := r.stCount + 1;
505	               end if;
506	            else
507	               v.stCount := (others => '0');
508	            end if;
509	         ----------------------------------------------------------------------
510	         when DUMP_S =>
511	            -- Incoming valid data
512	            if intAxisMaster.tValid = '1' then
513	               -- Destination has changed, complete current write
514	               if intAxisMaster.tDest /= r.dmaWrTrack.dest then
515	                  v.state := IDLE_S;
516	               else
517	                  -- Accept the data
518	                  v.slave.tReady := '1';
519	                  -- Check for last AXIS word
520	                  if intAxisMaster.tLast = '1' then
521	                     v.dmaWrTrack.inUse := '0';
522	                     if r.dmaWrTrack.metaEnable = '1' then
523	                        v.state := META_S;
524	                     else
525	                        v.state := RETURN_S;
526	                     end if;
527	                  end if;
528	               end if;
529	            end if;
530	         ----------------------------------------------------------------------
531	         when others =>
532	            v.state := RESET_S;
533	      end case;
534	
535	      -- Forward the state of the state machine
536	      if (v.state = IDLE_S) then
537	         v.dmaWrIdle := '1';
538	      else
539	         v.dmaWrIdle := '0';
540	      end if;
541	
542	      -- Combinatorial outputs before the reset
543	      intAxisSlave <= v.slave;
544	
545	      -- Reset
546	      if (axiRst = '1') then
547	         v := REG_INIT_C;
548	      end if;
549	
550	      -- Register the variable for next clock cycle
551	      rin <= v;
552	
553	      -- Registered Outputs
554	      axiWriteMaster <= r.wMaster;
555	      dmaWrDescReq   <= r.dmaWrDescReq;
556	      dmaWrDescRet   <= r.dmaWrDescRet;
557	      dmaWrIdle      <= r.dmaWrIdle;
558	
559	   end process comb;
560	
561	   seq : process (axiClk) is
562	   begin
563	      if (rising_edge(axiClk)) then
564	         r <= rin after TPD_G;
565	      end if;
566	   end process seq;
567	
568	   --------------------------
569	   -- Tracking RAM
570	   --------------------------
571	   U_TrackRam : entity surf.DualPortRam
572	      generic map (
573	         TPD_G         => TPD_G,
574	         MEMORY_TYPE_G => "block",
575	         REG_EN_G      => true,
576	         DOA_REG_G     => true,
577	         DOB_REG_G     => true,         -- 2 cycle read latency
578	         MODE_G        => "write-first",
579	         DATA_WIDTH_G  => AXI_WRITE_DMA_TRACK_SIZE_C,
580	         ADDR_WIDTH_G  => 8)
581	      port map (
582	         clka  => axiClk,
583	         wea   => '1',
584	         rsta  => axiRst,
585	         addra => r.dmaWrTrack.dest,
586	         dina  => trackDin,
587	         clkb  => axiClk,
588	         rstb  => axiRst,
589	         addrb => intAxisMaster.tDest,
590	         doutb => trackDout);
591	
592	   trackDin  <= toSlv(r.dmaWrTrack);
593	   trackData <= toAxiWriteDmaTrack(trackDout);
594	
595	end rtl;
596

