16	library ieee;
17	use ieee.std_logic_1164.all;
18	use ieee.std_logic_arith.all;
19	use ieee.std_logic_unsigned.all;
20	
21	
22	library surf;
23	use surf.StdRtlPkg.all;
24	use surf.AxiPkg.all;
25	use surf.AxiLitePkg.all;
26	use surf.AxiDmaPkg.all;
27	use surf.ArbiterPkg.all;
28	
29	entity AxiStreamDmaV2Desc is
30	   generic (
31	      TPD_G : time := 1 ns;
32	
33	      -- Number of read & write DMA engines to support for each descriptor engine
34	      CHAN_COUNT_G : integer range 1 to 16 := 1;
35	
36	      -- Base address of descriptor registers & FIFOs
37	      AXIL_BASE_ADDR_G : slv(31 downto 0) := x"00000000";
38	
39	      -- Configuration of AXI bus, must be 64 bits (or wider)
40	      AXI_CONFIG_G : AxiConfigType;
41	
42	      -- Number of descriptor entries in write FIFO and return ring buffers
43	      DESC_AWIDTH_G : integer range 4 to 32 := 12;
44	
45	      -- Choose between one-clock arbitration for return descriptors or count and check selection
46	      DESC_ARB_G : boolean := true;
47	
48	      -- Choose between inferred or xpm generated descriptor FIFOs
49	      DESC_SYNTH_MODE_G : string := "inferred";
50	
51	      -- Choose the type of resources for the descriptor FIFOs when DESC_SYNTH_MODE_G="xpm"
52	      DESC_MEMORY_TYPE_G : string := "block");
53	   port (
54	      -- Clock/Reset
55	      axiClk          : in  sl;
56	      axiRst          : in  sl;
57	      -- Local AXI Lite Bus
58	      axilReadMaster  : in  AxiLiteReadMasterType;
59	      axilReadSlave   : out AxiLiteReadSlaveType;
60	      axilWriteMaster : in  AxiLiteWriteMasterType;
61	      axilWriteSlave  : out AxiLiteWriteSlaveType;
62	      -- Additional signals
63	      interrupt       : out sl;
64	      online          : out slv(CHAN_COUNT_G-1 downto 0);
65	      acknowledge     : out slv(CHAN_COUNT_G-1 downto 0);
66	      -- DMA write descriptor request, ack and return
67	      dmaWrDescReq    : in  AxiWriteDmaDescReqArray(CHAN_COUNT_G-1 downto 0);
68	      dmaWrDescAck    : out AxiWriteDmaDescAckArray(CHAN_COUNT_G-1 downto 0);
69	      dmaWrDescRet    : in  AxiWriteDmaDescRetArray(CHAN_COUNT_G-1 downto 0);
70	      dmaWrDescRetAck : out slv(CHAN_COUNT_G-1 downto 0);
71	      -- DMA read descriptor request, ack and return
72	      dmaRdDescReq    : out AxiReadDmaDescReqArray(CHAN_COUNT_G-1 downto 0);
73	      dmaRdDescAck    : in  slv(CHAN_COUNT_G-1 downto 0);
74	      dmaRdDescRet    : in  AxiReadDmaDescRetArray(CHAN_COUNT_G-1 downto 0);
75	      dmaRdDescRetAck : out slv(CHAN_COUNT_G-1 downto 0);
76	      -- Config
77	      axiRdCache      : out slv(3 downto 0);
78	      axiWrCache      : out slv(3 downto 0);
79	      -- AXI Interface
80	      axiWriteMasters : out AxiWriteMasterArray(CHAN_COUNT_G-1 downto 0);
81	      axiWriteSlaves  : in  AxiWriteSlaveArray(CHAN_COUNT_G-1 downto 0);
82	
83	      -- Buffer Group Pause
84	      buffGrpPause : out slv(7 downto 0));
85	
86	end AxiStreamDmaV2Desc;
87	
88	architecture rtl of AxiStreamDmaV2Desc is
89	
90	   constant AXI_DESC_CONFIG_C : AxiConfigType := (
91	      ADDR_WIDTH_C => AXI_CONFIG_G.ADDR_WIDTH_C,
92	      DATA_BYTES_C => 16,               -- Force 128b descriptor
93	      ID_BITS_C    => AXI_CONFIG_G.ID_BITS_C,
94	      LEN_BITS_C   => AXI_CONFIG_G.LEN_BITS_C);
95	
96	   constant CHAN_SIZE_C : integer := bitSize(CHAN_COUNT_G-1);
97	   constant RET_COUNT_C : integer := CHAN_COUNT_G*2;
98	   constant RET_SIZE_C  : integer := bitSize(RET_COUNT_C-1);
99	
100	   constant RD_FIFO_CNT_C  : integer := 4;
101	   constant RD_FIFO_BITS_C : integer := RD_FIFO_CNT_C * 32;
102	
103	   constant WR_FIFO_CNT_C  : integer := 2;
104	   constant WR_FIFO_BITS_C : integer := WR_FIFO_CNT_C * 32;
105	
106	   type DescStateType is (
107	      IDLE_S,
108	      WRITE_S,
109	      READ_S,
110	      WAIT_S);
111	
112	   type RegType is record
113	      -- Write descriptor interface
114	      dmaWrDescAck    : AxiWriteDmaDescAckArray(CHAN_COUNT_G-1 downto 0);
115	      dmaWrDescRetAck : slv(CHAN_COUNT_G-1 downto 0);
116	
117	      -- Read descriptor interface
118	      dmaRdDescReq    : AxiReadDmaDescReqArray(CHAN_COUNT_G-1 downto 0);
119	      dmaRdDescRetAck : slv(CHAN_COUNT_G-1 downto 0);
120	
121	      -- AXI-Lite Register Access
122	      axilReadSlave  : AxiLiteReadSlaveType;
123	      axilWriteSlave : AxiLiteWriteSlaveType;
124	
125	      -- AXI4 Descriptor
126	      axiWriteMaster : AxiWriteMasterType;
127	
128	      -- Configuration
129	      wrBaseAddr  : slv(63 downto 0);   -- For wr ring buffer
130	      rdBaseAddr  : slv(63 downto 0);   -- For rd ring buffer
131	      maxSize     : slv(31 downto 0);
132	      contEn      : sl;
133	      dropEn      : sl;
134	      enable      : sl;
135	      forceInt    : sl;
136	      intEnable   : sl;
137	      online      : slv(CHAN_COUNT_G-1 downto 0);
138	      acknowledge : slv(CHAN_COUNT_G-1 downto 0);
139	      fifoReset   : sl;
140	      intSwAckReq : sl;
141	      intAckCount : slv(31 downto 0);
142	      descWrCache : slv(3 downto 0);
143	      buffRdCache : slv(3 downto 0);
144	      buffWrCache : slv(3 downto 0);
145	      enableCnt   : slv(7 downto 0);
146	      idBuffThold : Slv32Array(7 downto 0);
147	      wrTimeout   : slv(31 downto 0);
148	
149	      -- FIFOs
150	      fifoDin        : slv(31 downto 0);
151	      wrFifoWr       : slv(WR_FIFO_CNT_C-1 downto 0);
152	      rdFifoWr       : slv(RD_FIFO_CNT_C-1 downto 0);
153	      addrFifoSel    : sl;
154	      wrFifoRd       : sl;
155	      wrFifoValidDly : slv(1 downto 0);
156	      wrAddrValid    : sl;
157	      rdFifoRd       : sl;
158	      rdFifoValidDly : slv(1 downto 0);
159	      rdAddrValid    : sl;
160	
161	      -- Write Desc Request
162	      wrReqValid  : sl;
163	      wrReqCnt    : natural range 0 to CHAN_COUNT_G-1;
164	      wrReqNum    : slv(CHAN_SIZE_C-1 downto 0);
165	      wrReqAcks   : slv(CHAN_COUNT_G-1 downto 0);
166	      wrReqMissed : slv(31 downto 0);
167	
168	      -- Desc Return
169	      descRetList : slv(RET_COUNT_C-1 downto 0);
170	      descState   : DescStateType;
171	      descRetCnt  : natural range 0 to RET_COUNT_C-1;
172	      descRetNum  : slv(RET_SIZE_C-1 downto 0);
173	      descRetAcks : slv(RET_COUNT_C-1 downto 0);
174	      wrIndex     : slv(DESC_AWIDTH_G-1 downto 0);
175	      wrMemAddr   : slv(63 downto 0);
176	      rdIndex     : slv(DESC_AWIDTH_G-1 downto 0);
177	      rdMemAddr   : slv(63 downto 0);
178	      intReqEn    : sl;
179	      intReqCount : slv(31 downto 0);
180	      interrupt   : sl;
181	
182	      intHoldoff      : slv(15 downto 0);
183	      intHoldoffCount : slv(15 downto 0);
184	
185	      idBuffCount : Slv32Array(7 downto 0);
186	
187	      idBuffInc : slv(7 downto 0);
188	      idBuffDec : slv(7 downto 0);
189	
190	      buffGrpPause : slv(7 downto 0);
191	   end record RegType;
192	
193	   constant REG_INIT_C : RegType := (
194	      -- Write descriptor interface
195	      dmaWrDescAck    => (others => AXI_WRITE_DMA_DESC_ACK_INIT_C),
196	      dmaWrDescRetAck => (others => '0'),
197	      -- Read descriptor interface
198	      dmaRdDescReq    => (others => AXI_READ_DMA_DESC_REQ_INIT_C),
199	      dmaRdDescRetAck => (others => '0'),
200	      -- AXI-Lite Register Access
201	      axilReadSlave   => AXI_LITE_READ_SLAVE_INIT_C,
202	      axilWriteSlave  => AXI_LITE_WRITE_SLAVE_INIT_C,
203	      -- AXI4 Descriptor
204	      axiWriteMaster  => axiWriteMasterInit(AXI_DESC_CONFIG_C, '1', "01", "0000"),
205	      -- Configuration
206	      wrBaseAddr      => (others => '0'),
207	      rdBaseAddr      => (others => '0'),
208	      maxSize         => (others => '0'),
209	      contEn          => '0',
210	      dropEn          => '0',
211	      enable          => '0',
212	      forceInt        => '0',
213	      intEnable       => '0',
214	      online          => (others => '0'),
215	      acknowledge     => (others => '0'),
216	      fifoReset       => '1',
217	      intSwAckReq     => '0',
218	      intAckCount     => (others => '0'),
219	      descWrCache     => (others => '0'),
220	      buffRdCache     => (others => '0'),
221	      buffWrCache     => (others => '0'),
222	      enableCnt       => (others => '0'),
223	      idBuffThold     => (others => (others => '0')),
224	      wrTimeout       => x"0000FFFF",
225	      -- FIFOs
226	      fifoDin         => (others => '0'),
227	      wrFifoWr        => (others => '0'),
228	      rdFifoWr        => (others => '0'),
229	      addrFifoSel     => '0',
230	      wrFifoRd        => '0',
231	      wrFifoValidDly  => (others => '0'),
232	      wrAddrValid     => '0',
233	      rdFifoRd        => '0',
234	      rdFifoValidDly  => (others => '0'),
235	      rdAddrValid     => '0',
236	      -- Write Desc Request
237	      wrReqValid      => '0',
238	      wrReqCnt        => 0,
239	      wrReqNum        => (others => '0'),
240	      wrReqAcks       => (others => '0'),
241	      wrReqMissed     => (others => '0'),
242	      -- Desc Return
243	      descRetList     => (others => '0'),
244	      descState       => IDLE_S,
245	      descRetCnt      => 0,
246	      descRetNum      => (others => '0'),
247	      descRetAcks     => (others => '0'),
248	      wrIndex         => (others => '0'),
249	      wrMemAddr       => (others => '0'),
250	      rdIndex         => (others => '0'),
251	      rdMemAddr       => (others => '0'),
252	      intReqEn        => '0',
253	      intReqCount     => (others => '0'),
254	      interrupt       => '0',
255	      intHoldoff      => toSlv(10000, 16),  -- ~20 kHz
256	      intHoldoffCount => (others => '0'),
257	      idBuffCount     => (others => (others => '0')),
258	      idBuffInc       => (others => '0'),
259	      idBuffDec       => (others => '0'),
260	      buffGrpPause    => (others => '0'));
261	
262	   signal r   : RegType := REG_INIT_C;
263	   signal rin : RegType;
264	
265	   signal rdFifoValid : slv(RD_FIFO_CNT_C-1 downto 0);
266	   signal rdFifoDout  : slv(RD_FIFO_BITS_C-1 downto 0);
267	
268	   signal wrFifoValid : slv(WR_FIFO_CNT_C-1 downto 0);
269	   signal wrFifoDout  : slv(WR_FIFO_BITS_C-1 downto 0);
270	
271	   signal intSwAckEn   : sl;
272	   signal intCompValid : sl;
273	   signal intDiffValid : sl;
274	   signal invalidCount : sl;
275	   signal diffCnt      : slv(31 downto 0);
276	
277	   signal holdoffCompare : sl;
278	   signal idBuffCompare  : slv(7 downto 0);
279	
280	   -- attribute dont_touch                 : string;
281	   -- attribute dont_touch of r            : signal is "true";
282	   -- attribute dont_touch of intSwAckEn   : signal is "true";
283	   -- attribute dont_touch of invalidCount : signal is "true";
284	   -- attribute dont_touch of diffCnt      : signal is "true";
285	
286	begin
287	
288	   assert (AXI_CONFIG_G.ADDR_WIDTH_C <= 40)
289	      report "AXI_CONFIG_G.ADDR_WIDTH_C (" & integer'image(AXI_CONFIG_G.ADDR_WIDTH_C) & ") must be <= 40" severity failure;
290	
291	   -----------------------------------------
292	   -- Write Free List FIFOs
293	   -----------------------------------------
294	   U_DescGen : for i in 0 to WR_FIFO_CNT_C-1 generate
295	      U_DescFifo : entity surf.Fifo
296	         generic map (
297	            TPD_G           => TPD_G,
298	            GEN_SYNC_FIFO_G => true,
299	            FWFT_EN_G       => true,
300	            DATA_WIDTH_G    => 32,
301	            ADDR_WIDTH_G    => DESC_AWIDTH_G,
302	            SYNTH_MODE_G    => DESC_SYNTH_MODE_G,
303	            MEMORY_TYPE_G   => DESC_MEMORY_TYPE_G)
304	         port map (
305	            rst    => r.fifoReset,
306	            wr_clk => axiClk,
307	            wr_en  => r.wrFifoWr(i),
308	            din    => r.fifoDin,
309	            rd_clk => axiClk,
310	            rd_en  => r.wrFifoRd,
311	            dout   => wrFifoDout((i*32)+31 downto i*32),
312	            valid  => wrFifoValid(i));
313	   end generate;
314	
315	   -----------------------------------------
316	   -- Read Transaction FIFOs
317	   -----------------------------------------
318	   U_RdFifoGen : for i in 0 to RD_FIFO_CNT_C-1 generate
319	      U_RdFifo : entity surf.Fifo
320	         generic map (
321	            TPD_G           => TPD_G,
322	            GEN_SYNC_FIFO_G => true,
323	            FWFT_EN_G       => true,
324	            DATA_WIDTH_G    => 32,
325	            ADDR_WIDTH_G    => DESC_AWIDTH_G,
326	            SYNTH_MODE_G    => DESC_SYNTH_MODE_G,
327	            MEMORY_TYPE_G   => DESC_MEMORY_TYPE_G)
328	         port map (
329	            rst    => r.fifoReset,
330	            wr_clk => axiClk,
331	            wr_en  => r.rdFifoWr(i),
332	            din    => r.fifoDin,
333	            rd_clk => axiClk,
334	            rd_en  => r.rdFifoRd,
335	            dout   => rdFifoDout((i*32)+31 downto i*32),
336	            valid  => rdFifoValid(i));
337	   end generate;
338	
339	   -----------------------------------------
340	   -- Interrupt ACK Counter
341	   -----------------------------------------
342	
343	   -- Check for invalid count
344	   U_invalidCount : entity surf.DspComparator
345	      generic map (
346	         TPD_G   => TPD_G,
347	         WIDTH_G => 32)
348	      port map (
349	         clk     => axiClk,
350	         ibValid => r.intSwAckReq,
351	         ain     => r.intReqCount,
352	         bin     => r.intAckCount,
353	         obValid => intCompValid,
354	         ls      => invalidCount);  --  (a <  b) <--> r.intAckCount > r.intReqCount
355	
356	   U_diffCnt : entity surf.DspAddSub
357	      generic map (
358	         TPD_G   => TPD_G,
359	         WIDTH_G => 32)
360	      port map (
361	         clk     => axiClk,
362	         ibValid => r.intSwAckReq,
363	         ain     => r.intReqCount,
364	         bin     => r.intAckCount,
365	         add     => '0',                -- '0' = subtract
366	         obValid => intDiffValid,       -- sync'd up with U_DspComparator
367	         pOut    => diffCnt);      -- a - b <--> r.intReqCount - r.intAckCount
368	
369	   -- Both DSPs are done
370	   intSwAckEn <= intDiffValid and intCompValid;
371	
372	   U_holdoffCompare : entity surf.DspComparator
373	      generic map (
374	         TPD_G   => TPD_G,
375	         WIDTH_G => 16)
376	      port map (
377	         clk  => axiClk,
378	         ain  => r.intHoldoffCount,
379	         bin  => r.intHoldoff,
380	         gtEq => holdoffCompare);  --  (a >= b) <--> r.intHoldoffCount >= r.intHoldoff
381	
382	   U_Pause : for i in 0 to 7 generate
383	      U_DspComparator : entity surf.DspComparator
384	         generic map (
385	            TPD_G   => TPD_G,
386	            WIDTH_G => 32)
387	         port map (
388	            clk  => axiClk,
389	            ain  => r.idBuffCount(i),
390	            bin  => r.idBuffThold(i),
391	            gtEq => idBuffCompare(i));  --  (a >= b) <--> r.idBuffCount(i) >= r.idBuffThold(i)
392	   end generate;
393	
394	   -----------------------------------------
395	   -- Control Logic
396	   -----------------------------------------
397	
398	   comb : process (axiRst, axiWriteSlaves, axilReadMaster, axilWriteMaster,
399	                   diffCnt, dmaRdDescAck, dmaRdDescRet, dmaWrDescReq,
400	                   dmaWrDescRet, holdoffCompare, idBuffCompare, intSwAckEn,
401	                   invalidCount, r, rdFifoDout, rdFifoValid, wrFifoDout,
402	                   wrFifoValid) is
403	      variable v            : RegType;
404	      variable wrReqList    : slv(CHAN_COUNT_G-1 downto 0);
405	      variable descRetValid : sl;
406	      variable descIndex    : natural;
407	      variable dmaRdReq     : AxiReadDmaDescReqType;
408	      variable rdIndex      : natural;
409	      variable regCon       : AxiLiteEndPointType;
410	      variable idIncrement  : slv(7 downto 0);
411	      variable idDecrement  : slv(7 downto 0);
412	      variable wStrbIdx     : natural;
413	   begin
414	
415	      -- Latch the current value
416	      v := r;
417	
418	      -- Clear one shot signals
419	      v.rdFifoWr    := (others => '0');
420	      v.rdFifoRd    := '0';
421	      v.wrFifoWr    := (others => '0');
422	      v.wrFifoRd    := '0';
423	      v.acknowledge := (others => '0');
424	      v.idBuffInc   := (others => '0');
425	      v.idBuffDec   := (others => '0');
426	
427	      ----------------------------------------------------------
428	      -- Register access
429	      ----------------------------------------------------------
430	
431	      -- Start transaction block
432	      axiSlaveWaitTxn(regCon, axilWriteMaster, axilReadMaster, v.axilWriteSlave, v.axilReadSlave);
433	
434	      axiSlaveRegister(regCon, x"000", 0, v.enable);
435	      axiSlaveRegisterR(regCon, x"000", 8, r.enableCnt);  -- Count the number of times enable transitions from 0->1
436	      axiSlaveRegisterR(regCon, x"000", 16, '1');  -- Legacy DESC_128_EN_C constant (always 0x1 now)
437	      axiSlaveRegisterR(regCon, x"000", 24, toSlv(5, 8));  -- Version Number for aes-stream-driver to case on
438	      axiSlaveRegister(regCon, x"004", 0, v.intEnable);
439	      axiSlaveRegister(regCon, x"008", 0, v.contEn);
440	      axiSlaveRegister(regCon, x"00C", 0, v.dropEn);
441	      axiSlaveRegister(regCon, x"010", 0, v.wrBaseAddr(31 downto 0));
442	      axiSlaveRegister(regCon, x"014", 0, v.wrBaseAddr(63 downto 32));
443	      axiSlaveRegister(regCon, x"018", 0, v.rdBaseAddr(31 downto 0));
444	      axiSlaveRegister(regCon, x"01C", 0, v.rdBaseAddr(63 downto 32));
445	      axiSlaveRegister(regCon, x"020", 0, v.fifoReset);
446	      axiSlaveRegister(regCon, x"028", 0, v.maxSize);
447	      axiSlaveRegister(regCon, x"02C", 0, v.online);
448	      axiSlaveRegister(regCon, x"030", 0, v.acknowledge);
449	
450	      axiSlaveRegisterR(regCon, x"034", 0, toSlv(CHAN_COUNT_G, 8));
451	      axiSlaveRegisterR(regCon, x"034", 8, toSlv(AXI_CONFIG_G.ADDR_WIDTH_C, 8));
452	      axiSlaveRegisterR(regCon, x"034", 16, toSlv(AXI_CONFIG_G.DATA_BYTES_C, 8));
453	      axiSlaveRegisterR(regCon, x"038", 0, toSlv(DESC_AWIDTH_G, 8));
454	      axiSlaveRegister(regCon, x"03C", 0, v.descWrCache);
455	      axiSlaveRegister(regCon, x"03C", 8, v.buffWrCache);
456	      axiSlaveRegister(regCon, x"03C", 12, v.buffRdCache);
457	
458	      axiSlaveRegister(regCon, x"040", 0, v.fifoDin);
459	      axiWrDetect(regCon, x"040", v.rdFifoWr(0));
460	
461	      axiSlaveRegister(regCon, x"044", 0, v.fifoDin);
462	      axiWrDetect(regCon, x"044", v.rdFifoWr(1));
463	
464	      axiSlaveRegister(regCon, x"048", 0, v.fifoDin);
465	      axiWrDetect(regCon, x"048", v.wrFifoWr(0));
466	
467	      axiSlaveRegister(regCon, x"04C", 0, v.intAckCount(15 downto 0));
468	      axiSlaveRegister(regCon, x"04C", 17, v.intEnable);
469	      axiWrDetect(regCon, x"04C", v.intSwAckReq);
470	
471	      axiSlaveRegisterR(regCon, x"050", 0, r.intReqCount);
472	      axiSlaveRegisterR(regCon, x"054", 0, r.wrIndex);
473	      axiSlaveRegisterR(regCon, x"058", 0, r.rdIndex);
474	
475	      axiSlaveRegisterR(regCon, x"05C", 0, r.wrReqMissed);
476	
477	      axiSlaveRegister(regCon, x"060", 0, v.fifoDin);
478	      axiWrDetect(regCon, x"060", v.rdFifoWr(2));
479	
480	      axiSlaveRegister(regCon, x"064", 0, v.fifoDin);
481	      axiWrDetect(regCon, x"064", v.rdFifoWr(3));
482	
483	      axiSlaveRegister(regCon, x"070", 0, v.fifoDin);
484	      axiWrDetect(regCon, x"070", v.wrFifoWr(1));
485	
486	      axiSlaveRegister(regCon, x"080", 0, v.forceInt);
487	
488	      axiSlaveRegister(regCon, x"084", 0, v.intHoldoff);
489	
490	      axiSlaveRegister(regCon, x"088", 0, v.wrTimeout);
491	
492	      for i in 0 to 7 loop
493	         axiSlaveRegister(regCon, toSlv(144 + i*4, 12), 0, v.idBuffThold(i));  -- 0x090 - 0xAC
494	         axiSlaveRegisterR(regCon, toSlv(176 + i*4, 12), 0, r.idBuffCount(i));  -- 0x0B0 - 0xCC
495	         axiWrDetect(regCon, toSlv(176 + i*4, 12), v.idBuffDec(i));  -- 0x0B0 - 0xCC
496	      end loop;
497	
498	      -- End transaction block
499	      axiSlaveDefault(regCon, v.axilWriteSlave, v.axilReadSlave, AXI_RESP_DECERR_C);
500	
501	      ----------------------------------------------------------
502	      -- Address FIFO Control
503	      ----------------------------------------------------------
504	
505	      -- Alternate between read and write FIFOs to common address pool
506	      v.addrFifoSel := not(r.addrFifoSel);
507	
508	      -- Write pipeline
509	      if r.wrFifoRd = '1' then
510	         v.wrFifoValidDly := (others => '0');
511	         v.wrAddrValid    := '0';
512	      else
513	         v.wrFifoValidDly := (uAnd(wrFifoValid) and (not r.addrFifoSel)) & r.wrFifoValidDly(1);
514	         if r.wrFifoValidDly(0) = '1' then
515	            v.wrAddrValid := '1';
516	         end if;
517	      end if;
518	
519	      -- Read pipeline
520	      if r.rdFifoRd = '1' then
521	         v.rdFifoValidDly := (others => '0');
522	         v.rdAddrValid    := '0';
523	      else
524	         v.rdFifoValidDly := (uAnd(rdFifoValid) and r.addrFifoSel) & r.rdFifoValidDly(1);
525	         if r.rdFifoValidDly(0) = '1' then
526	            v.rdAddrValid := '1';
527	         end if;
528	      end if;
529	
530	      ----------------------------------------------------------
531	      -- Write Descriptor Requests (A.K.A "Arbitration" logic)
532	      ----------------------------------------------------------
533	
534	      -- Clear acks
535	      for i in 0 to CHAN_COUNT_G-1 loop
536	         v.dmaWrDescAck(i).valid := '0';
537	      end loop;
538	
539	      -- Arbitrate
540	      if r.wrReqValid = '0' then
541	
542	         -- Format requests
543	         wrReqList := (others => '0');
544	         for i in 0 to CHAN_COUNT_G-1 loop
545	            wrReqList(i) := dmaWrDescReq(i).valid;
546	         end loop;
547	
548	         -- Arbitrate between requesters
549	         if r.enable = '1' and r.wrFifoRd = '0' and r.wrAddrValid = '1' then
550	            if (DESC_ARB_G = true) then
551	               arbitrate(wrReqList, r.wrReqNum, v.wrReqNum, v.wrReqValid, v.wrReqAcks);
552	            else
553	
554	               -- Check the counter
555	               if (r.wrReqCnt = (CHAN_COUNT_G-1)) then
556	                  -- Reset the counter
557	                  v.wrReqCnt := 0;
558	               else
559	                  -- Increment the counter
560	                  v.wrReqCnt := r.wrReqCnt + 1;
561	               end if;
562	
563	               -- Check for valid
564	               if (wrReqList(r.wrReqCnt) = '1') then
565	                  v.wrReqValid := '1';
566	                  v.wrReqNum   := toSlv(r.wrReqCnt, CHAN_SIZE_C);
567	               else
568	                  v.wrReqValid := '0';
569	               end if;
570	
571	            end if;
572	         end if;
573	
574	         if wrReqList /= 0 and uAnd(wrFifoValid) = '0' then
575	            v.wrReqMissed := r.wrReqMissed + 1;
576	         end if;
577	
578	      -- Valid arbitration result
579	      else
580	         for i in 0 to CHAN_COUNT_G-1 loop
581	
582	            v.dmaWrDescAck(i).address(63 downto 40) := (others => '0');
583	            v.dmaWrDescAck(i).address(39 downto 4)  := wrFifoDout(63 downto 28);
584	            v.dmaWrDescAck(i).address(3 downto 0)   := (others => '0');
585	
586	            v.dmaWrDescAck(i).dropEn  := r.dropEn;
587	            v.dmaWrDescAck(i).contEn  := r.contEn;
588	            v.dmaWrDescAck(i).maxSize := r.maxSize;
589	            v.dmaWrDescAck(i).timeout := r.wrTimeout;
590	
591	            v.dmaWrDescAck(i).buffId(27 downto 0) := wrFifoDout(27 downto 0);
592	
593	         end loop;
594	
595	         v.dmaWrDescAck(conv_integer(r.wrReqNum)).valid := '1';
596	         v.wrFifoRd                                     := '1';
597	         v.wrReqValid                                   := '0';
598	
599	         v.idBuffInc(conv_integer(dmaWrDescReq(conv_integer(r.wrReqNum)).id(2 downto 0))) := '1';
600	
601	      end if;
602	
603	      ----------------------------------------------------------
604	      -- Read/Write Descriptor Returns
605	      ----------------------------------------------------------
606	
607	      if CHAN_COUNT_G > 1 then
608	         descIndex := conv_integer(r.descRetNum(RET_SIZE_C-1 downto 1));
609	      else
610	         descIndex := 0;
611	      end if;
612	
613	      -- Clear acks
614	      v.dmaWrDescRetAck := (others => '0');
615	      v.dmaRdDescRetAck := (others => '0');
616	
617	      -- Axi Cache
618	      v.axiWriteMaster.awcache := r.descWrCache;
619	
620	      -- Reset strobing Signals
621	      if (axiWriteSlaves(descIndex).awready = '1') then
622	         v.axiWriteMaster.awvalid := '0';
623	      end if;
624	      if (axiWriteSlaves(descIndex).wready = '1') then
625	         v.axiWriteMaster.wvalid := '0';
626	         v.axiWriteMaster.wlast  := '0';
627	      end if;
628	
629	      -- Generate descriptor ring addresses
630	      v.wrMemAddr := r.wrBaseAddr + (r.wrIndex & "0000");
631	      v.rdMemAddr := r.rdBaseAddr + (r.rdIndex & "0000");
632	
633	      -- State machine
634	      case r.descState is
635	         ----------------------------------------------------------------------
636	         when IDLE_S =>
637	
638	            -- Format requests
639	            v.descRetList := (others => '0');
640	            for i in 0 to CHAN_COUNT_G-1 loop
641	               v.descRetList(i*2)   := dmaWrDescRet(i).valid;
642	               v.descRetList(i*2+1) := dmaRdDescRet(i).valid;
643	            end loop;
644	
645	            -- Arbitrate between requesters
646	            if r.enable = '1' then
647	               if (DESC_ARB_G = true) then
648	                  arbitrate(v.descRetList, r.descRetNum, v.descRetNum, descRetValid, v.descRetAcks);
649	               else
650	
651	                  -- Check the counter
652	                  if (r.descRetCnt = (RET_COUNT_C-1)) then
653	                     -- Reset the counter
654	                     v.descRetCnt := 0;
655	                  else
656	                     -- Increment the counter
657	                     v.descRetCnt := r.descRetCnt + 1;
658	                  end if;
659	
660	                  -- Check for valid
661	                  if (v.descRetList(r.descRetCnt) = '1') then
662	                     descRetValid := '1';
663	                     v.descRetNum := toSlv(r.descRetCnt, RET_SIZE_C);
664	                  else
665	                     descRetValid := '0';
666	                  end if;
667	
668	               end if;
669	
670	               -- Valid request
671	               if descRetValid = '1' then
672	                  if v.descRetNum(0) = '1' then
673	                     v.descState := READ_S;
674	                  else
675	                     v.descState := WRITE_S;
676	                  end if;
677	               end if;
678	            end if;
679	
680	         ----------------------------------------------------------------------
681	         when WRITE_S =>
682	
683	            -- Write address channel
684	            v.axiWriteMaster.awaddr := r.wrMemAddr;
685	            v.axiWriteMaster.awlen  := x"00";  -- Single transaction
686	
687	            -- Write data channel
688	            v.axiWriteMaster.wlast := '1';
689	
690	            -- Descriptor data, 128-bits
691	            v.axiWriteMaster.wdata(127)            := '1';
692	            v.axiWriteMaster.wdata(126 downto 108) := (others => '0');
693	            v.axiWriteMaster.wdata(107 downto 104) := toSlv(descIndex, 4);  -- Channel
694	            v.axiWriteMaster.wdata(103 downto 96)  := dmaWrDescRet(descIndex).dest;
695	            v.axiWriteMaster.wdata(95 downto 64)   := dmaWrDescRet(descIndex).size;
696	            v.axiWriteMaster.wdata(63 downto 32)   := dmaWrDescRet(descIndex).buffId;
697	            v.axiWriteMaster.wdata(31 downto 24)   := dmaWrDescRet(descIndex).firstUser;
698	            v.axiWriteMaster.wdata(23 downto 16)   := dmaWrDescRet(descIndex).lastUser;
699	            v.axiWriteMaster.wdata(15 downto 8)    := dmaWrDescRet(descIndex).id;
700	            v.axiWriteMaster.wdata(7 downto 5)     := (others => '0');
701	            v.axiWriteMaster.wdata(4)              := dmaWrDescRet(descIndex).result(3);
702	            v.axiWriteMaster.wdata(3)              := dmaWrDescRet(descIndex).continue;
703	            v.axiWriteMaster.wdata(2 downto 0)     := dmaWrDescRet(descIndex).result(2 downto 0);
704	
705	            v.axiWriteMaster.awvalid := '1';
706	            v.axiWriteMaster.wvalid  := '1';
707	            v.wrIndex                := r.wrIndex + 1;
708	            v.descState              := WAIT_S;
709	
710	            v.dmaWrDescRetAck(descIndex) := '1';
711	
712	         ----------------------------------------------------------------------
713	         when READ_S =>
714	            if CHAN_COUNT_G > 1 then
715	               descIndex := conv_integer(r.descRetNum(RET_SIZE_C-1 downto 1));
716	            else
717	               descIndex := 0;
718	            end if;
719	
720	            -- Write address channel
721	            v.axiWriteMaster.awaddr := r.rdMemAddr;
722	            v.axiWriteMaster.awlen  := x"00";  -- Single transaction
723	
724	            -- Write data channel
725	            v.axiWriteMaster.wlast := '1';
726	
727	            -- Descriptor data, 128-bits
728	            v.axiWriteMaster.wdata(127)           := '1';
729	            v.axiWriteMaster.wdata(126 downto 64) := (others => '0');
730	            v.axiWriteMaster.wdata(63 downto 32)  := dmaRdDescRet(descIndex).buffId;
731	            v.axiWriteMaster.wdata(31 downto 3)   := (others => '0');
732	            v.axiWriteMaster.wdata(2 downto 0)    := dmaRdDescRet(descIndex).result;
733	
734	            v.axiWriteMaster.awvalid := '1';
735	            v.axiWriteMaster.wvalid  := '1';
736	            v.rdIndex                := r.rdIndex + 1;
737	            v.descState              := WAIT_S;
738	
739	            v.dmaRdDescRetAck(descIndex) := '1';
740	
741	         ----------------------------------------------------------------------
742	         when WAIT_S =>
743	            if v.axiWriteMaster.awvalid = '0' and v.axiWriteMaster.wvalid = '0' then
744	               v.intReqEn  := '1';
745	               v.descState := IDLE_S;
746	            end if;
747	      ----------------------------------------------------------------------
748	      end case;
749	
750	      -- Section A3.4.3 Data read and write structure: Write strobes - Narrow transfers
751	      v.axiWriteMaster.wstrb        := (others => '0');
752	      -- Check for 64-bit or 128-bit case
753	      if (AXI_CONFIG_G.DATA_BYTES_C <= 16) then
754	         -- Always 16 byte WSTRB (64-bit case to break apart into two cycle implemented in surf.AxiStreamDmaV2WriteMux)
755	         v.axiWriteMaster.wstrb(15 downto 0) := x"FFFF";
756	
757	      -- Else 256-bits (or more) case
758	      else
759	         -- Find the 128-bit word offset
760	         wStrbIdx := conv_integer(v.axiWriteMaster.awaddr(log2(AXI_CONFIG_G.DATA_BYTES_C) - 1 downto 4));
761	
762	         -- Assign the WSTRB to this offset
763	         v.axiWriteMaster.wstrb((wStrbIdx*16+15) downto (wStrbIdx*16)) := x"FFFF";
764	      end if;
765	
766	      -- Copy the lowest words to the entire bus (refer to  "section 9.3 Narrow transfers" of the AMBA spec)
767	      for i in (AXI_MAX_DATA_WIDTH_C/128)-1 downto 1 loop
768	         v.axiWriteMaster.wdata((128*i)+127 downto (128*i)) := v.axiWriteMaster.wdata(127 downto 0);
769	      end loop;
770	
771	      -- Drive interrupt, avoid false firings during ack
772	      if ((r.intReqCount /= 0 and holdoffCompare = '1') or r.forceInt = '1') and r.intSwAckReq = '0' then
773	         v.interrupt := r.intEnable;
774	      else
775	         v.interrupt := '0';
776	      end if;
777	
778	      -- Ack request from software
779	      if r.intSwAckReq = '1' then
780	         v.forceInt := '0';
781	
782	         -- DSPs are done
783	         if intSwAckEn = '1' then
784	            v.intSwAckReq := '0';
785	
786	            -- Just in case
787	            if invalidCount = '1' then    -- r.intAckCount > r.intReqCount
788	               v.intReqCount := (others => '0');
789	            else
790	               v.intReqCount := diffCnt;  -- r.intReqCount - r.intAckCount
791	            end if;
792	         end if;
793	
794	      -- Firmware posted an entry
795	      elsif r.intReqEn = '1' then
796	         v.intReqCount := r.intReqCount + 1;
797	         v.intReqEn    := '0';
798	      end if;
799	
800	      -- Check if we need to reset IRQ holdoff counter
801	      if r.intSwAckReq = '1' then
802	         v.intHoldoffCount := (others => '0');
803	
804	      -- Check if not max value
805	      elsif r.intHoldoffCount /= x"FFFF" then
806	         v.intHoldoffCount := r.intHoldoffCount + 1;
807	      end if;
808	
809	      ----------------------------------------------------------
810	      -- Read Descriptor Requests
811	      ----------------------------------------------------------
812	
813	      -- Clear requests
814	      for i in 0 to CHAN_COUNT_G-1 loop
815	         if dmaRdDescAck(i) = '1' then
816	            v.dmaRdDescReq(i).valid := '0';
817	         end if;
818	      end loop;
819	
820	      dmaRdReq       := AXI_READ_DMA_DESC_REQ_INIT_C;
821	      dmaRdReq.valid := r.rdAddrValid;
822	
823	      -- Format request, 128-bits
824	      dmaRdReq.address(63 downto 40) := (others => '0');
825	      dmaRdReq.address(39 downto 4)  := rdFifoDout(127 downto 92);
826	      dmaRdReq.address(3 downto 0)   := (others => '0');
827	      dmaRdReq.buffId(27 downto 0)   := rdFifoDout(91 downto 64);
828	      dmaRdReq.size                  := rdFifoDout(63 downto 32);
829	      dmaRdReq.firstUser             := rdFifoDout(31 downto 24);
830	      dmaRdReq.lastUser              := rdFifoDout(23 downto 16);
831	      dmaRdReq.dest                  := rdFifoDout(15 downto 8);
832	      dmaRdReq.continue              := rdFifoDout(3);
833	
834	      rdIndex := conv_integer(rdFifoDout(7 downto 4));
835	
836	      -- Pull next entry if we are not waiting for ack on given channel
837	      if r.rdFifoRd = '0' and dmaRdReq.valid = '1' and v.dmaRdDescReq(rdIndex).valid = '0' then
838	         v.dmaRdDescReq(rdIndex) := dmaRdReq;
839	         v.rdFifoRd              := '1';
840	      end if;
841	
842	      ----------------------------------------------------------
843	      -- Buffer Group Tracking
844	      ----------------------------------------------------------
845	      for i in 0 to 7 loop
846	
847	         if r.idBuffInc(i) = '1' and r.idBuffDec(i) = '0' then
848	            v.idBuffCount(i) := r.idBuffCount(i) + 1;
849	
850	         elsif r.idBuffInc(i) = '0' and r.idBuffDec(i) = '1' then
851	            v.idBuffCount(i) := r.idBuffCount(i) - 1;
852	
853	         end if;
854	
855	         if r.idBuffThold(i) /= 0 then
856	            v.buffGrpPause(i) := idBuffCompare(i);  -- r.idBuffCount(i) > r.idBuffThold(i)
857	         else
858	            v.buffGrpPause(i) := '0';
859	         end if;
860	
861	      end loop;
862	
863	      ----------------------------------------------------------
864	      -- Check if disabled
865	      ----------------------------------------------------------
866	      if r.enable = '0' then
867	         v.wrIndex         := (others => '0');
868	         v.rdIndex         := (others => '0');
869	         v.wrReqMissed     := (others => '0');
870	         v.idBuffCount     := (others => (others => '0'));
871	         v.intHoldoffCount := (others => '0');
872	         v.intReqEn        := '0';
873	         v.intReqCount     := (others => '0');
874	         v.interrupt       := '0';
875	         v.forceInt        := '0';
876	      end if;
877	
878	      if (r.enable = '0') and (v.enable = '1') and (r.enableCnt /= x"FF") then
879	         v.enableCnt := r.enableCnt + 1;
880	      end if;
881	
882	      ----------------------------------------------------------
883	      -- Outputs
884	      ----------------------------------------------------------
885	
886	      axilReadSlave  <= r.axilReadSlave;
887	      axilWriteSlave <= r.axilWriteSlave;
888	
889	      buffGrpPause <= r.buffGrpPause;
890	
891	      online          <= r.online;
892	      interrupt       <= r.interrupt;
893	      acknowledge     <= r.acknowledge;
894	      dmaWrDescAck    <= r.dmaWrDescAck;
895	      dmaWrDescRetAck <= r.dmaWrDescRetAck;
896	      dmaRdDescReq    <= r.dmaRdDescReq;
897	      dmaRdDescRetAck <= r.dmaRdDescRetAck;
898	      axiRdCache      <= r.buffRdCache;
899	      axiWrCache      <= r.buffWrCache;
900	
901	      axiWriteMasters <= (others => r.axiWriteMaster);
902	
903	      -- Only assert one master
904	      for i in 0 to CHAN_COUNT_G-1 loop
905	         if descIndex /= i then
906	            axiWriteMasters(i).awvalid <= '0';
907	            axiWriteMasters(i).wvalid  <= '0';
908	         end if;
909	      end loop;
910	
911	      ----------------------------------------------------------
912	      -- Reset
913	      ----------------------------------------------------------
914	      if (axiRst = '1') then
915	         v := REG_INIT_C;
916	      end if;
917	
918	      -- Register the variable for next clock cycle
919	      rin <= v;
920	
921	   end process comb;
922	
923	   seq : process (axiClk) is
924	   begin
925	      if (rising_edge(axiClk)) then
926	         r <= rin after TPD_G;
927	      end if;
928	   end process seq;
929	
930	end rtl;
931

